window.TPP_DAILY=window.TPP_DAILY||{};window.TPP_DAILY["infant"]={"aug":{"theme":"Welcome to Our Den","weeks":[{"label":"Week 1 — Hello, Little One","days":[{"day":"Monday","focus":"Warm Hellos","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Name-Song Welcome","d":"Cuddle up and sing “Hel-lo, hel-lo, hello baby ___” to the tune of any lullaby. Hearing their own name in your voice tells baby: you belong here."},{"t":"Gentle Hand Trace","d":"Hold baby’s hand and softly trace each tiny finger while you talk about your day. Your calm touch and voice build the trust everything else grows from."}]},{"day":"Tuesday","focus":"One Little You","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"One Kiss Count","d":"Kiss one little nose and say “one!” Then one hand, one tummy, one toe — always naming “one.” Baby is soaking up number words long before counting."},{"t":"One Photo Focus","d":"Prop one family photo where baby can see it during floor time. Point and say, “One Mama.” Simple, single things help young eyes settle and focus."}]},{"day":"Wednesday","focus":"Cozy Textures","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Fuzzy & Smooth","d":"Let baby feel a fuzzy sock, then a cool wooden spoon (always supervise). Comparing textures is baby’s very first science experiment."},{"t":"Blanket Nest Tummy Time","d":"Roll a towel under baby’s chest for a short tummy-time stretch on a familiar blanket. A minute or two at a time builds strong neck and shoulders."}]},{"day":"Thursday","focus":"Voices of Home","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Echo the Coo","d":"When baby coos, copy the sound, then wait for a reply. This little back-and-forth conversation teaches baby that their voice matters."},{"t":"Storytime Snuggle","d":"Read any board book in a slow, sing-song voice at cuddle time. Babies listen for the music of your words long before the meaning."}]},{"day":"Friday","focus":"Our Family Faces","domains":["Social Studies","Creative Expression"],"opts":[{"t":"Family Face Parade","d":"Show photos of the people who love baby — grandma, cousins, the family pet — and name each one. Learning “my people” is baby’s very first social studies."},{"t":"Rock & Hum","d":"Sway with baby to “The More We Get Together,” humming a verse close to their cheek. The gentle buzz of your hum is soothing and musical all at once."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tuck these by the rocking chair — tiny welcomes, big trust.","items":["A “sing baby’s name” hello-song card for the fridge.","One family photo card to prop near floor time.","A simple wake-feed-play-sleep routine strip.","A texture-touch tip card: one soft thing, one bumpy thing a day."]}},{"label":"Week 2 — Songs & Sounds of A","days":[{"day":"Monday","focus":"The Ahh Sound","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Sing the Ahh","d":"Sing “ahh-ahh-apple” softly during cuddle time, stretching the A sound long and silly. Babies learn sounds from hearing them played with, not from flashcards."},{"t":"Ahh Mirror Faces","d":"Hold baby at the mirror and make big, slow “ahh” mouths together. Watching your lips move is exactly how babies map new sounds."}]},{"day":"Tuesday","focus":"Body Drum Beats","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Pat-Pat Rhythm","d":"Gently pat a slow beat on baby’s tummy while you chant a nursery rhyme. Feeling rhythm on the body helps babies sense language before they speak it."},{"t":"Kick the Jingle","d":"Lay baby on their back with a soft jingling toy near their feet and let them kick at it (always supervise). Every kick builds leg strength and cause-and-effect smarts."}]},{"day":"Wednesday","focus":"Listen & Find","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Find That Sound","d":"Shake a rattle gently off to one side and watch baby turn to find it. Tracking a sound is real detective work for a young brain."},{"t":"Quiet-Loud Game","d":"Whisper baby’s name, then say it in a bright, cheery voice. Noticing the difference between soft and loud is early listening science."}]},{"day":"Thursday","focus":"Lap Song Library","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Piggy Toes","d":"Play “This Little Piggy” on baby’s toes, pausing before the wiggly ending. That waiting moment builds anticipation — an early thinking skill."},{"t":"Rhyme & Read","d":"Read a rhyming board book and let your voice bounce with the rhythm. Rhyme tunes baby’s ear for the sounds hiding inside words."}]},{"day":"Friday","focus":"One in Our World","domains":["Mathematical Thinking","Social Studies"],"opts":[{"t":"One Spoon Helper","d":"At mealtime, hand baby one soft spoon to hold while you feed with another, saying “one spoon for you.” Tiny mealtime jobs are baby’s first taste of helping the family."},{"t":"One Red Thing Tour","d":"Carry baby around the room finding one red thing at a time — “one red cup.” Naming things one at a time plants the seed of counting."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Slip these into the diaper bag — songs make the whole day go smoother.","items":["A lap-rhyme cheat sheet: Piggy, Pat-a-Cake, Row Your Boat.","An “ahh is for apple” sound card to sing at snack time.","A tip card: pat a slow beat while you chant a rhyme.","One red circle card to spot around the house together."]}},{"label":"Week 3 — Reach, Roll & the B Sound","days":[{"day":"Monday","focus":"The Buh Sound","domains":["Language & Literacy","Physical Development"],"opts":[{"t":"Buh-Buh Bounce","d":"Bounce baby gently on your knee chanting “buh-buh-baby.” Pairing a sound with a bounce helps it stick in a growing brain."},{"t":"Bubble Watch","d":"Blow a few bubbles just out of reach and let baby track them as they drift (always supervise). Following slow-moving bubbles is a workout for young eyes."}]},{"day":"Tuesday","focus":"Reach & Grasp","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Just-Out-of-Reach Toy","d":"Place a favorite soft toy a hand’s width away during tummy time. That little stretch to reach it builds muscles and stick-with-it spirit."},{"t":"Scarf Pull Surprise","d":"Tuck a light scarf into an empty tissue box and let baby pull it out again and again (always supervise). Pull, repeat, delight — that’s how babies study the world."}]},{"day":"Wednesday","focus":"Circles Everywhere","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Round Things Tour","d":"Gather a few big round things — a soft ball, a plastic bowl, a round lid — and let baby pat each one as you say “circle.” Shape words sink in through the hands first."},{"t":"Rolling Ball Watch","d":"Roll a soft ball slowly across the floor while baby watches from tummy time. Tracking a rolling ball teaches how objects move — baby physics."}]},{"day":"Thursday","focus":"Books & Belonging","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Point & Name Read","d":"Read a sturdy board book and point to one picture on each page: “ball… baby… bear.” Point-and-name is how books first start to make sense."},{"t":"Lovey Hello","d":"Help baby’s soft lovey wave “hello” and gently boop baby’s nose. Little pretend moments like this grow warm feelings about friends."}]},{"day":"Friday","focus":"Out & About","domains":["Social Studies","Creative Expression"],"opts":[{"t":"Stroller Neighborhood Tour","d":"Take a slow stroller loop and narrate your world: “There’s the mail truck. There’s a dog.” Baby is learning the neighborhood — community starts here."},{"t":"Red Scarf Dance","d":"Float a red scarf up and let it drift down onto baby’s toes while you sing. Color, motion, and music, all in one giggly package."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Pin these to the fridge — reach, roll, and giggle all week long.","items":["A tummy-time tip card: place the toy a hand’s width away.","A tissue-box scarf-pull how-to.","A “buh is for baby” bounce chant.","A stroller-walk narration card: name three things you see."]}},{"label":"Week 4 — Cozy C & Our Whole Den","days":[{"day":"Monday","focus":"The Cuh Sound","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Cuh-Cuh Cuddle","d":"Snuggle close and play with the C sound: “cuh-cuh-cuddle, cuh-cuh-cozy.” Silly sound play now becomes easy letter learning later."},{"t":"Cup Stack Topple","d":"Stack two big plastic cups and let baby knock them down, again and again. Every topple teaches cause and effect — and it never gets old."}]},{"day":"Tuesday","focus":"Peekaboo Pros","domains":["Social & Emotional Development","Scientific Inquiry"],"opts":[{"t":"Blanket Peekaboo","d":"Hide your face behind a burp cloth, then pop out with a soft “peekaboo.” Baby is learning that people who disappear come back — big security in a tiny game."},{"t":"Toy Under the Towel","d":"Half-hide a toy under a towel and see if baby pulls it free. Finding hidden things is a real brain milestone called object permanence."}]},{"day":"Wednesday","focus":"Strong Little Bodies","domains":["Physical Development","Mathematical Thinking"],"opts":[{"t":"Row-Boat Rocking","d":"Hold baby’s hands and rock gently to “Row, Row, Row Your Boat” while they sit supported on your lap. Gentle rocking builds core strength and balance."},{"t":"One-Toy Basket","d":"Put one soft toy in a basket, tip it out, and say “one.” Refill and repeat — in-and-out play with number words is baby math at its finest."}]},{"day":"Thursday","focus":"Read & Rest","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Goodnight Book Ritual","d":"Pick one calm board book to read at the same time every day this week. Repetition turns a book into an old friend — and reading into a habit."},{"t":"Lullaby Face Time","d":"Hum a slow lullaby while baby watches your face. Your changing expressions are baby’s favorite show, and humming is their first music class."}]},{"day":"Friday","focus":"Our Whole Den","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Who Loves You Tour","d":"Walk baby past the family photos and name everyone who loves them, ending at the mirror: “and here’s our baby.” A strong sense of “my people” starts this small."},{"t":"Family Song Circle","d":"Invite whoever’s home to sit in a circle and sing one favorite song to baby. Being sung to by their people tells baby: this is where I belong."}]}],"homeden":{"title":"The Home Den — This Week","lead":"One month down — tape these up and celebrate your little one.","items":["A “cuh is for cuddle” sound card for snuggle time.","A peekaboo step-up card: face, then toy, then half-hidden toy.","A bedtime-book routine card: same book, same time.","A “who loves baby” photo-tour checklist."]}}]},"sep":{"theme":"All About Me & My Family","weeks":[{"label":"Week 1 — This Is Me & My Family","days":[{"day":"Monday","focus":"Face to Face","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Mirror Play","d":"Hold baby up to a mirror. Point and gently name “eyes… nose… mouth,” and smile together. Babies love faces — especially yours."},{"t":"Family Photo Peek","d":"Show 2–3 family photos up close. Name each face: “That’s Mama! That’s you!” Naming builds belonging."}]},{"day":"Tuesday","focus":"Name & Voice","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Hello Name Song","d":"Sing softly while you cuddle: “Hello, hello, hello baby ___.” Hearing their name sung builds connection and language."},{"t":"Narrate the Day","d":"Use baby’s name as you go: “___ is having a bath!” Words grow from hearing them all day long."}]},{"day":"Wednesday","focus":"Little Senses","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Texture Touch","d":"Let baby feel a soft blanket, then a crinkly toy. Watch their face change — that curiosity is learning. (Always supervise.)"},{"t":"Rattle & Wait","d":"Shake a rattle, then pause. Give baby a moment to ‘answer’ with a wiggle or sound. Back-and-forth wires the brain."}]},{"day":"Thursday","focus":"Serve & Return","domains":["Approaches to Learning","Language & Literacy"],"opts":[{"t":"Coo Conversation","d":"Copy the sound baby makes, then wait. Copy it again. This gentle back-and-forth is powerful brain-building."},{"t":"Peekaboo Scarf","d":"Hide your face with a light scarf, then “peekaboo!” Repeat as long as the smiles last — it teaches that you always come back."}]},{"day":"Friday","focus":"Cuddle & Connect","domains":["Social & Emotional Development","Creative Expression"],"opts":[{"t":"Lap-Time Song","d":"Bounce gently to “This Little Piggy” or “The More We Get Together.” Rhythm + closeness = happy learning."},{"t":"Snuggle Read-Aloud","d":"Read in a soft, sing-song voice — a family board book or Your Feelings Matter. Babies drink in the sound of your voice."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Pop these in the diaper bag — little moments, big bonding.","items":["A family photo card to keep near baby’s crib.","A ‘serve-and-return’ tip card (copy baby’s sounds, then pause).","A lullaby list for the car and bedtime.","A ‘sign MORE with me’ half-sheet for mealtimes."]}},{"label":"Week 2 — Little Hands, Little Signs","days":[{"day":"Monday","focus":"Sign for More","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"More, Please","d":"At feeding time, press your fingertips together to sign “more” before each bite. Babies can talk with their hands months before words come."},{"t":"All Done Wave","d":"When the meal ends, open your hands wide and sign “all done” with a smile. Giving baby a way to say “finished” heads off many tears."}]},{"day":"Tuesday","focus":"The Sss Sound","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Snake Song Sss","d":"Stretch the S sound in a soft, silly hiss — “sss-sss-so sweet” — during cuddle time. Playing with one sound at a time tunes baby’s ear."},{"t":"Sock Puppet Sings","d":"Slip a sock over your hand and have it “sing” a gentle song to baby. A singing sock gets more giggles than it has any right to."}]},{"day":"Wednesday","focus":"Two by Two","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Two Hands Clap","d":"Take baby’s two hands and clap them gently together: “one, two.” Feeling the count in their own body plants early number sense."},{"t":"Two-Sock Tug","d":"Let baby tug at their two socks during a diaper change while you count them aloud. Tugging builds hand strength, and counting builds math ears."}]},{"day":"Thursday","focus":"Little Explorer","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Two Cups, One Toy","d":"Hide a toy under one of two big cups and lift to find it, tapping each cup as you count “one, two.” Searching is baby science in action."},{"t":"Warm & Cool Touch","d":"Let baby touch a warm (not hot) washcloth, then a cool one, naming each. Comparing how things feel is the seed of science."}]},{"day":"Friday","focus":"My People & Me","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Family Book Time","d":"Read a board book about families in your coziest chair, naming the feelings on each face as you go. Warm laps make strong readers."},{"t":"Wave to the Helpers","d":"From a window or on a walk, wave together to the mail carrier or a passing neighbor. Community begins with a wave."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Clip these to the high chair — little hands have a lot to say.","items":["A “sign more with me” mealtime picture card.","An “all done” sign how-to for the whole family.","A “sss is for so sweet” sound card.","A count-two-things card: two hands, two socks, two cheeks."]}},{"label":"Week 3 — The People Who Love Me","days":[{"day":"Monday","focus":"Mama & Dada","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Mama-Dada Chant","d":"Chant “ma-ma-ma” and “da-da-da” softly, pausing so baby can try a sound back. Those repeated syllables are the building blocks of first words."},{"t":"Photo Kiss Goodnight","d":"At bedtime, help baby “kiss” a family photo goodnight as you name each person. Little rituals like this grow a deep sense of belonging."}]},{"day":"Tuesday","focus":"Faces & Feelings","domains":["Social & Emotional Development","Creative Expression"],"opts":[{"t":"Silly-Face Mirror Duet","d":"Make a happy face, a surprised face, and a sleepy face together at the mirror, naming each one. Reading faces is baby’s first emotional vocabulary."},{"t":"Happy-Sleepy Song Swap","d":"Sing “If You’re Happy and You Know It” in a big bright voice, then once more slow and sleepy. Feeling the difference teaches more than words can."}]},{"day":"Wednesday","focus":"Squares & Orange","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Square Touch Tour","d":"Carry baby to the window, a picture frame, and the cracker box, tracing each square edge with their hand and saying “square.” Shape words soak in through the fingertips."},{"t":"Orange Watch","d":"Set one orange thing — a toy, a cup, a real orange — in front of baby during floor play and name its color as they explore it (always supervise). One bold color at a time suits young eyes best."}]},{"day":"Thursday","focus":"Strong & Steady","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Sit & Reach","d":"Sit baby between your legs and place a soft toy just to one side, then the other. Twisting to reach builds balance and a can-do spirit."},{"t":"Pillow Hill Tummy Time","d":"Drape baby chest-down over a firm pillow for a new tummy-time view (stay right beside them). A tiny change of angle keeps practice feeling fresh."}]},{"day":"Friday","focus":"Story of Us","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Our Family Story","d":"Read a family board book, then tell baby one tiny true story about their own family. Stories about us are the first history lessons."},{"t":"Grandparent Hello Call","d":"Play a short voice message or video call from a grandparent or auntie and watch baby light up. Faraway family still counts as close."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tape these by the changing table — family is the whole curriculum this week.","items":["A mama-dada chant card for diaper changes.","A family-faces name game: point, name, kiss.","A square-tracing card: window, frame, cracker box.","A call-a-grandparent reminder slip."]}},{"label":"Week 4 — Look How I’ve Grown","days":[{"day":"Monday","focus":"My Hands & Toes","domains":["Physical Development","Language & Literacy"],"opts":[{"t":"Toes-to-Nose Naming","d":"During a diaper change, gently bring baby’s toes up and name parts as you go: “toes… knees… tummy… nose.” Body words are some of the first words babies understand."},{"t":"Head-to-Toes Book","d":"Read a body-parts board book, touching baby’s own nose and toes to match the pages. Connecting pictures to their real body makes books click."}]},{"day":"Tuesday","focus":"Sounds I Make","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Babble Back Band","d":"Turn baby’s babble into a duet — echo their sounds in a sing-song voice and add one new one. You’re the lead singer they’re learning from."},{"t":"Sss & Smile Reprise","d":"Sing the S sound into familiar words — “sss-so big, sss-so sweet” — while rocking. Ending the month with our special sound helps it settle in."}]},{"day":"Wednesday","focus":"Two of Me","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Two Feet Bicycle","d":"Lay baby down and gently bicycle their two legs while counting “one, two, one, two.” Rhythmic counting plus movement is a full-body math lesson."},{"t":"Two Cups Tower","d":"Stack two big cups, count “one, two,” and let baby topple them. Build, count, crash, repeat — that’s how math starts."}]},{"day":"Thursday","focus":"So Big Discoveries","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Drop It Again","d":"Sit baby in the high chair and let them drop a soft toy over the side a few times while you fetch it. Dropping games are baby’s gravity experiments — annoying and brilliant at once."},{"t":"Echo Cup Coo","d":"Talk to baby through a large plastic cup held near your mouth, then hold it gently near theirs to catch a coo (you keep hold of the cup). Hearing voices change is a little sound-science show."}]},{"day":"Friday","focus":"Celebrate Me","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"So-Big Celebration","d":"“How big is baby? Sooo big!” Stretch baby’s arms gently overhead and grin together. Celebrating little wins teaches baby that growing feels good."},{"t":"Month of Me Album","d":"Flip through this month’s photos with baby, naming who and where: “That’s you with Grandpa.” Looking back at their own little life is social studies, baby-sized."}]}],"homeden":{"title":"The Home Den — This Week","lead":"One sweet month of you and baby — tuck these up on the fridge.","items":["A “sooo big” stretch-and-cheer card.","A body-parts naming card for diaper changes.","A drop-and-fetch patience tip for high-chair time.","A month-in-photos memory page to fill in."]}}]},"oct":{"theme":"The Great Outdoors","weeks":[{"label":"Week 1 — Leaves & Trees","days":[{"day":"Monday","focus":"Hello, Autumn","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Leaf in Hand","d":"On a stroller walk, pick one big clean leaf and let baby hold and crinkle it (always supervise — leaves head for mouths fast). One real leaf beats a basket of plastic toys."},{"t":"Tree Gaze Blanket","d":"Spread a blanket under a tree and let baby watch the branches sway overhead. Dappled light and moving leaves are nature’s first mobile."}]},{"day":"Tuesday","focus":"The Tuh Sound","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Tick-Tock Tap","d":"Tap a steady tick-tock beat on baby’s tummy while saying “t-t-tick-tock.” One playful sound at a time is exactly how phonics starts."},{"t":"Tree Talk Touch","d":"Guide baby’s hand to a tree trunk and say “t-t-tree.” Pairing the sound with something real and rough helps it stick."}]},{"day":"Wednesday","focus":"Falling Leaves","domains":["Creative Expression","Physical Development"],"opts":[{"t":"Scarf Leaf Float","d":"Float a light scarf up and let it drift down like a falling leaf while you sing “the leaves are falling down.” Watching it builds tracking eyes; reaching for it builds muscles."},{"t":"Leaf Crunch Bag","d":"Seal a few dry leaves inside a zip-top bag, tape it shut, and let baby pat the crunch (always supervise). Big autumn sound, safe little hands."}]},{"day":"Thursday","focus":"Tree Stories","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Leafy Read-Aloud","d":"Read a fall board book — or any favorite — outside on a blanket if the weather’s kind. A new place makes an old book feel brand new."},{"t":"Rock-a-Bye Branches","d":"Sway with baby to “Rock-a-Bye Baby,” pointing up at the real treetops. A classic lullaby means more with the wind in view."}]},{"day":"Friday","focus":"Brown All Around","domains":["Mathematical Thinking","Social Studies"],"opts":[{"t":"Three Brown Things","d":"On a walk, find three brown things — a tree trunk, a park bench, the dirt — counting each one aloud. Baby hears numbers and colors out in the real world, where they belong."},{"t":"Park Bench People-Watch","d":"Sit on a bench and quietly narrate the passing world: “A dog. A jogger. A stroller friend.” The neighborhood is baby’s first map."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tuck these in the stroller basket — the outdoors is baby’s first classroom.","items":["A “listen for the birds” walk card.","One clean leaf to tape near the changing table.","The t-t-tick-tock sound card.","A three-brown-things counting card."]}},{"label":"Week 2 — Wind & Sky","days":[{"day":"Monday","focus":"Feel the Breeze","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Breeze on Cheeks","d":"Step outside and let a gentle breeze touch baby’s cheeks: “wind.” Naming what they feel connects words to the world."},{"t":"Be the Wind","d":"Blow the softest puff of air on baby’s arm, then their toes, and watch the surprise. You’re the wind they can giggle at."}]},{"day":"Tuesday","focus":"The Juh Sound","domains":["Language & Literacy","Physical Development"],"opts":[{"t":"J-J-Jiggle Song","d":"Hold baby and do a gentle j-j-jiggle bounce, chanting “jiggle, jiggle, jump.” A sound baby can feel in their whole body is a sound they remember."},{"t":"Jack in the Knees","d":"“Jack-in-the-box, sits so still… pop.” Lift baby gently up on the pop. Anticipation games build memory and belly laughs."}]},{"day":"Wednesday","focus":"Sky & Song","domains":["Approaches to Learning","Creative Expression"],"opts":[{"t":"Cloud Watch Cuddle","d":"Lie back with baby on your chest and watch the clouds drift, narrating lazily: “big fluffy one… little wispy one.” Slow watching grows long attention."},{"t":"Twinkle at Twilight","d":"Sing “Twinkle, Twinkle” at the window as the sky darkens. Same song, new backdrop — that’s how babies learn the world changes."}]},{"day":"Thursday","focus":"Three in the Sky","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Count Three Birds","d":"When birds pass or land nearby, count them softly with baby: “one, two, three birds.” Counting real, moving things is math with wings."},{"t":"Sunny-Shady Switch","d":"Move baby’s blanket from sun to shade and back, naming “warm” and “cool” (never linger in direct sun). Feeling the difference is honest-to-goodness science."}]},{"day":"Friday","focus":"Windy-Day Stories","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Weather Report Baby","d":"Look out the window together each morning and give a two-word weather report: “Windy day.” Baby is learning that families check the sky before heading out."},{"t":"Breezy Book Nook","d":"Read a board book beside an open window and let the curtain flutter as you turn pages. A little breeze turns storytime into an event."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Clip these by the door — wind and sky are free entertainment.","items":["A cloud-watching cuddle card for slow afternoons.","The j-j-jiggle bounce chant.","A two-word weather-report card for each morning.","A count-three-birds walk card."]}},{"label":"Week 3 — Little Creatures","days":[{"day":"Monday","focus":"The Guh Sound","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"G-G-Giggle Game","d":"Say “g-g-giggle” and wiggle your fingers in the air above baby’s tummy, then land one gentle tickle. The G sound plus giggles equals instant phonics."},{"t":"G-G-Go Song","d":"Chant “ready, set, g-g-go” before lifting baby up from each diaper change. A tiny routine phrase becomes a favorite game by Friday."}]},{"day":"Tuesday","focus":"Bug Watch","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Follow That Ant","d":"Find a busy ant or beetle outside and watch it together from baby’s blanket (look, don’t touch). Tracking a tiny mover is great exercise for growing eyes."},{"t":"Wiggle Like a Worm","d":"Lay baby on a blanket and do a gentle full-body wiggle song together: “wiggle like a worm.” Copying creature moves builds body awareness."}]},{"day":"Wednesday","focus":"Gentle Hands","domains":["Social & Emotional Development","Creative Expression"],"opts":[{"t":"Pet the Puppet Gently","d":"Guide baby’s hand to stroke a soft animal toy: “gentle… gentle.” Practicing soft touches now pays off with pets and friends later."},{"t":"Animal Sound Serenade","d":"Sing “Old MacDonald” slowly, leaning close for each animal sound. Baby studies your mouth making moos and quacks — a singing lesson and a show in one."}]},{"day":"Thursday","focus":"Three Little Friends","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Three-Toy Lineup","d":"Line up three soft animal toys and count them with baby’s hand tapping each: “one, two, three.” Touch-counting is how numbers become real."},{"t":"Reach for the Duck","d":"Hold a soft toy just above baby during back time and let them bat and reach for it. Every swipe strengthens shoulders and aim."}]},{"day":"Friday","focus":"Creature Storytime","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Animal Book Safari","d":"Read an animal board book and pause so baby can pat each picture. Books are how babies meet lions without leaving your lap."},{"t":"Neighborhood Dog Hello","d":"On a walk, watch a neighborhood dog from a comfy distance and narrate: “The dog says woof.” Learning who shares our world — furry friends included — is social studies for babies."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Pop these in the diaper bag — this week we’re wild about little creatures.","items":["A gentle-hands practice card: pet the toy, then the pet.","The g-g-giggle sound game card.","A watch-an-ant walk card (look, don’t touch).","A three-toy touch-counting card."]}},{"label":"Week 4 — Textures of Fall","days":[{"day":"Monday","focus":"Touch the Season","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Pinecone Pat","d":"Hold a large pinecone steady while baby pats its bumpy scales (your hands stay on it the whole time). Bumpy, smooth, crunchy — fall is a texture buffet."},{"t":"Basket of Fall","d":"Gather a few big fall finds — a smooth gourd, a large pinecone, a crunchy leaf — and hold each one steady while baby pats it (your hands stay on every item). Real objects teach more than any toy aisle."}]},{"day":"Tuesday","focus":"Triangle Time","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Triangle Trace","d":"Cut one big paper triangle, tape it low on the wall, and trace its three sides with baby’s finger: “one, two, three.” Shape plus counting, all in one touch."},{"t":"Triangle Tour","d":"Tape three paper triangles at baby height around the room and visit each one, saying “triangle” at every stop. Repetition in new spots makes the shape feel like a friend."}]},{"day":"Wednesday","focus":"Fall Music & Motion","domains":["Creative Expression","Physical Development"],"opts":[{"t":"Drum the Pumpkin","d":"Sit baby beside a pumpkin and pat it like a drum together, slow then fast. Homegrown percussion builds rhythm and arm strength."},{"t":"Sweater Sway","d":"Put on a cozy song and sway with baby cheek-to-cheek in your softest sweater. Music plus warm textures makes memories you can’t buy."}]},{"day":"Thursday","focus":"Cozy Story Season","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Blanket Fort Read","d":"Drape a blanket over two chairs, snuggle inside, and read a book in your soft new cave. Cozy spaces make books feel like treasure."},{"t":"Thankful Whisper","d":"At bedtime, whisper three things you love about baby into their ear. They won’t remember the words — they’ll remember the feeling."}]},{"day":"Friday","focus":"Our Outdoor Month","domains":["Social Studies","Approaches to Learning"],"opts":[{"t":"Season Souvenir Walk","d":"Take one last October walk and pick one big bright leaf together, letting baby pat it in your hand at every stop (keep it out of little mouths). Tiny traditions become family culture."},{"t":"Window World Tour","d":"Visit each window in the house and narrate what’s outside: “Our tree. Our street. Our world.” Home is baby’s first neighborhood map."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tape these where you’ll see them — one crunchy, cozy month well spent.","items":["A fall-textures list to pat from your hand: gourd, pinecone, crunchy leaf.","A triangle-tracing wall card.","A blanket-fort storytime invitation.","A thankful-whisper bedtime card."]}}]},"nov":{"theme":"Thankful Hearts","weeks":[{"label":"Week 1 — Warm & Cozy Hearts","days":[{"day":"Monday","focus":"Soft & Snuggly","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Blanket Nest Cuddle","d":"Make a little nest of soft blankets on the floor and lie face-to-face with baby. Let tiny hands explore each texture while you talk softly. Warm touch builds secure attachment."},{"t":"Warm Towel Hello","d":"Right after a bath, wrap baby in a warm towel and rock slowly while you hum. Name what you feel — warm, soft, cozy. Calm routines teach baby the world is safe."}]},{"day":"Tuesday","focus":"Happy H Sounds","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Ha-Ha Laugh Game","d":"Hold baby on your lap and say a breathy “ha-ha-ha,” then pause and wait. When baby wiggles or coos, laugh right back. That /h/ sound is baby’s first little Bear Phonics moment."},{"t":"Hum and Sway","d":"Hum a favorite tune while swaying baby gently side to side. Stop humming now and then and watch baby ask for more with a kick or a coo. Pauses invite baby into the music."}]},{"day":"Wednesday","focus":"Little Explorers","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Tummy Time Treasure","d":"Spread a blanket and place one soft, interesting item — a fabric square or a board book — just out of reach during tummy time. Reaching and stretching builds the muscles behind crawling. Stay right there the whole time."},{"t":"Mirror Tummy Time","d":"Prop an unbreakable mirror in front of baby during tummy time. That fascinating friend in the glass keeps heads lifting longer, and lifting builds strong neck and trunk muscles."}]},{"day":"Thursday","focus":"Thankful Faces","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Thankful Face Chat","d":"Hold baby up to see your face and say what you’re thankful for — “I’m thankful for you.” Smile big. Babies read faces long before words, and yours is the favorite."},{"t":"Kiss-the-Hand Game","d":"Kiss baby’s hand, then offer your hand for a “kiss” back — any touch counts. Narrate the love: “Thank you for that sweet kiss.” Serve-and-return like this wires the brain for connection."}]},{"day":"Friday","focus":"Story & Snuggle","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Lap Book Time","d":"Settle baby on your lap with any sturdy board book and read a few pages, pointing at the pictures. It’s fine if baby pats or mouths the book — that is what reading looks like at this age."},{"t":"Who Loves You Album","d":"Look through photos of the people who love baby and name each one — “That’s Grandma.” Babies begin learning who their people are one familiar face at a time."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tuck these in the diaper bag — cozy little moments for a thankful week.","items":["Whisper happy /h/ sounds during diaper changes — hug, hat, ha-ha.","A few extra minutes of tummy time after naps — even three counts.","Point out something yellow on every walk — a leaf, a sign, a flower.","End the day naming one thing you’re both thankful for, out loud."]}},{"label":"Week 2 — Thankful for My Family","days":[{"day":"Monday","focus":"Kisses & Coos","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"K Sound Kisses","d":"Say a crisp “k-k-k” near baby’s cheek, then land a kiss. Sprinkle in k words all day — kiss, kick, cozy. Baby’s ears are cataloguing every sound you make."},{"t":"Babble Echo","d":"When baby babbles, echo the exact sound back and wait for a reply. This back-and-forth turn-taking is baby’s very first conversation, and you’re the favorite partner."}]},{"day":"Tuesday","focus":"Counting Toes","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Four Little Toes","d":"Count baby’s toes slowly up to four — “one, two, three, four” — with a gentle squeeze on each. Hearing numbers in a warm voice plants the seeds of counting."},{"t":"This Little Piggy","d":"Play This Little Piggy on fingers and toes, pausing before the wiggly ending so baby learns to anticipate it. Anticipation is early math — patterns and what comes next."}]},{"day":"Wednesday","focus":"Kitchen Discoveries","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Wooden Spoon Drum","d":"Sit baby safely on your lap or the floor and offer a wooden spoon and an upside-down pot. Every bang teaches cause and effect — I do this, and that happens."},{"t":"Measuring Cup Peek","d":"Hide a soft toy under a big plastic measuring cup, then lift it with a happy “there it is.” Object permanence — knowing hidden things still exist — is growing right now."}]},{"day":"Thursday","focus":"Family Faces","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Video Call Hello","d":"Have a short video call with a grandparent or cousin and help baby wave. Familiar voices from far away gently stretch baby’s little circle of loved ones."},{"t":"Thank You Rounds","d":"Carry baby around the house and thank the people (and pets) you meet — “Thank you, Daddy, for dinner.” Baby soaks in the warm rhythm of gratitude long before the words."}]},{"day":"Friday","focus":"Songs of Thanks","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"I’m Thankful Song","d":"Sing a simple made-up “I’m thankful for…” song to the tune of Frère Jacques, filling in baby’s name, your family, and a cozy blanket. Melodies help language stick."},{"t":"Thankful Book Cuddle","d":"Share a fall or thank-you board book, letting baby turn (or chew) the pages. Point to one picture per page and name it — labeling builds vocabulary long before first words."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Family is baby’s whole world — keep it close and chatty this week.","items":["Play “k-k-kiss” at pickup time — kiss, cuddle, cozy.","Count to four on fingers and toes at every diaper change.","Let baby’s hand trace a rectangle — a board book cover or a door.","One video call or photo visit with a faraway family member."]}},{"label":"Week 3 — Autumn Senses","days":[{"day":"Monday","focus":"Leaf Look & Listen","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Stroller Leaf Watch","d":"Take a slow stroller or carrier walk and stop under a tree. Let baby watch the leaves flutter and listen to the crunch under your feet. Outdoor light and motion feed growing senses."},{"t":"Big Leaf Touch","d":"Hold one large, clean leaf firmly in your own hand and let baby pat it while you say “leaf — bumpy, dry.” Keep it in your grip the whole time so nothing reaches the mouth."}]},{"day":"Tuesday","focus":"La-La Lap Songs","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"La-La-La Serenade","d":"Sing any tune using only “la-la-la” while bouncing baby gently on your knees. That /l/ sound gets little tongues wiggling — leaf, love, lap."},{"t":"Rock and Rhyme","d":"Rock slowly while reciting a nursery rhyme, letting your voice rise and fall. Rhythm and rhyme tune baby’s ear for the music inside language."}]},{"day":"Wednesday","focus":"Yellow Discoveries","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Yellow Hunt Carry","d":"Carry baby around the house pointing out yellow things — a banana, a towel, sunlight on the wall. Name the color each time; repetition is how color words take root."},{"t":"Sunny Window Watch","d":"Sit together by a sunny window and watch shadows and light slowly move. Narrate what you see. Quiet noticing together builds baby’s attention span."}]},{"day":"Thursday","focus":"Reach & Grasp","domains":["Physical Development","Mathematical Thinking"],"opts":[{"t":"Soft Block Topple","d":"Stack two or three soft blocks or folded washcloths and let baby swat the tower down. Cheer, rebuild, repeat. Up, down, more — that’s early math talk."},{"t":"Reach for the Rattle","d":"Hold a rattle just above baby’s chest during back play and let those arms stretch and swipe. Grasping practice builds the hand control behind every later skill."}]},{"day":"Friday","focus":"Grateful Story Time","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Bear Says Thanks Read","d":"Snuggle up with Bear Says Thanks or any cozy fall book and read in a soft, warm voice. Baby is learning that books mean closeness and calm."},{"t":"Whisper Thank Yous","d":"At bedtime, whisper three thank-yous into baby’s ear — name people, cuddles, and one moment from the day. Your gentle voice at day’s end is pure security."}]}],"homeden":{"title":"The Home Den — This Week","lead":"A little autumn, a lot of love — easy sensory moments for the week.","items":["Sing “la-la-la” with l words — leaf, love, lullaby.","One slow outdoor walk to watch leaves, wind, and sky.","Offer a big clean leaf to pat while you hold it (always supervise).","Read one cozy fall book before a nap."]}},{"label":"Week 4 — Grateful Together","days":[{"day":"Monday","focus":"Helping Hands","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Laundry Helper Chat","d":"Fold laundry with baby propped safely beside you, narrating each piece — “Daddy’s shirt, warm towel.” Offer a soft sock to hold. Being part of family jobs is baby’s first lesson in belonging."},{"t":"Wave and Thank","d":"Practice waving bye-bye and a “thank you” baby sign — fingers to chin, then out — at every hand-off today. Baby signs give little ones a voice before words come."}]},{"day":"Tuesday","focus":"Playful Sound Review","domains":["Creative Expression","Approaches to Learning"],"opts":[{"t":"H-K-L Song Mix","d":"Sing the alphabet song slowly and give a little bounce on H, K, and L. Baby won’t know letters yet — the playful sounds and rhythm are exactly the point."},{"t":"Pat-a-Cake Together","d":"Clap baby’s hands gently through pat-a-cake, slowing down for the “roll it” part. Familiar hand games build rhythm, memory, and the joy of doing things together."}]},{"day":"Wednesday","focus":"Cozy Textures","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Texture Tour","d":"Touch baby’s palm to four safe textures around the house — fuzzy blanket, smooth table, bumpy sweater, cool window. Name each one. Comparing textures is baby science."},{"t":"Crinkle and Grip","d":"Let baby grip a crinkly baby toy or a clean piece of wax paper while you keep hold of it too (always supervise). New sounds plus new textures light up curious brains."}]},{"day":"Thursday","focus":"Thankful Movement","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Bicycle Leg Thanks","d":"During a diaper change, pedal baby’s legs gently in a bicycle motion while naming things you’re thankful for. Movement plus your happy voice turns routine care into connection."},{"t":"Thankful Sway","d":"Cradle baby in your arms and sway slowly while humming a gentle tune, whispering one thank-you at each turn. Slow rhythmic motion soothes and builds body awareness at the same time."}]},{"day":"Friday","focus":"Feast of Love","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Feelings Faces Read","d":"Read Your Feelings Matter by Mrs. Bear and copy each feeling face while baby watches. Naming feelings out loud now builds the emotional vocabulary baby will use for life."},{"t":"Gratitude Table Tour","d":"Before a family meal, carry baby around the table to greet each person — “We’re thankful for Grandpa.” Baby feels the warmth of being counted in."}]}],"homeden":{"title":"The Home Den — This Week","lead":"One thankful week — keep it simple, snuggly, and said out loud.","items":["Sign and say “thank you” at every meal — baby is watching.","Give baby a soft sock or towel “job” during laundry time.","Bounce on H, K, and L during a slow alphabet song.","Whisper one thing you’re thankful for at bedtime tonight."]}}]},"dec":{"theme":"Lights & Traditions Around the World","weeks":[{"label":"Week 1 — Twinkle & Glow","days":[{"day":"Monday","focus":"Watching the Lights","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Twinkle Light Watch","d":"Dim the room and let baby gaze at a strand of soft twinkle lights from your lap, lights well out of reach (always supervise). Watch where those eyes travel — visual tracking is hard work for new eyes."},{"t":"Flashlight Slow Dance","d":"In a dim room, sweep a flashlight beam slowly across the ceiling while baby lies safely beside you. Following the glow builds eye muscles and quiet focus."}]},{"day":"Tuesday","focus":"Wow W Sounds","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Wow Window Chat","d":"Hold baby at the window and say a round, slow “wow” at whatever you see — “Wow, a bird.” That /w/ sound plus your delighted face teaches baby the world is worth noticing."},{"t":"Wave Hello Practice","d":"Give a big slow wave with a soft “w-w-wave” as family members come and go today. Waving is one of baby’s first words in gesture form."}]},{"day":"Wednesday","focus":"Shiny & Crinkly","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Safe Shine Explore","d":"Offer one large, safe shiny item — a metallic gift bag held firmly in your own hand — for baby to pat and crinkle (always supervise). New sights and sounds together grow busy little brains."},{"t":"Tissue Paper Kick","d":"Lay baby on their back and hold a sheet of tissue paper where feet can kick it, then put it safely away after (always supervise). Every crinkle rewards a kick — cause and effect in action."}]},{"day":"Thursday","focus":"Lap Song Glow","domains":["Creative Expression","Social & Emotional Development"],"opts":[{"t":"Twinkle Twinkle Rock","d":"Rock baby slowly while singing Twinkle, Twinkle, Little Star, opening and closing your hand like a star overhead. Soft song plus slow motion is a lullaby for the whole nervous system."},{"t":"This Little Light","d":"Sing This Little Light of Mine with baby’s hand riding on yours as it sways. Feeling the beat through your body teaches rhythm from the inside out."}]},{"day":"Friday","focus":"Cozy Book Glow","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Lights Book Snuggle","d":"Share a board book about lights or nighttime by lamplight, keeping your voice low and warm. Reading in the glow makes books feel like comfort."},{"t":"Point and Name","d":"On any page, point to one bright picture, name it, and pause. When baby looks where you point, that shared gaze is a real literacy milestone."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Little lights, low voices, big wonder — tuck these in the diaper bag.","items":["Five quiet minutes of twinkle-light watching from your lap (lights out of reach).","Say “wow” slowly at the window — w-w-wow.","Sing Twinkle, Twinkle at bedtime with a hand-star overhead.","Read one book by lamplight tonight."]}},{"label":"Week 2 — Family Traditions","days":[{"day":"Monday","focus":"Family Sounds & Stories","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"F-F-Family Sounds","d":"Blow a soft “fff” like you’re cooling soup, then use f words all day — family, fun, five. Baby’s ears are busy cataloguing every sound you make."},{"t":"Family Story Book","d":"Share a board book about families, or a small photo album, naming each person and tradition you see. Baby’s first history lessons are the people who love them."}]},{"day":"Tuesday","focus":"Five Little Fingers","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Five Finger Count","d":"Count baby’s fingers slowly to five with a gentle squeeze on each — then kiss the whole hand. Numbers delivered with love are the best kind."},{"t":"High Five Practice","d":"Hold your palm up and guide baby’s hand to a gentle high five. Reaching across the body to your hand builds coordination and connection at once."}]},{"day":"Wednesday","focus":"Kitchen Traditions","domains":["Social Studies","Scientific Inquiry"],"opts":[{"t":"Smell the Spices","d":"Hold a jar of cinnamon or vanilla yourself and waft the scent gently toward baby, naming it. Scent memories tie straight into family and tradition."},{"t":"Stir and Narrate","d":"Wear or seat baby safely away from the stove while you cook a family favorite, narrating every step — “Now we stir.” Kitchen talk is rich, real language."}]},{"day":"Thursday","focus":"Green & Cozy","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Green Things Tour","d":"Carry baby around pointing out green — a plant, a towel, a blanket. Say “green” each time. One color across many objects is exactly how color concepts form."},{"t":"Watch the Watering","d":"Let baby watch you water a houseplant, touching one sturdy leaf with your own hand as you say “green leaf.” Watching you explore teaches baby how to explore."}]},{"day":"Friday","focus":"Songs from Home","domains":["Creative Expression","Social & Emotional Development"],"opts":[{"t":"Childhood Lullaby Share","d":"Sing a lullaby from your own childhood, in whatever language it lives in. Songs carried from your family to baby are traditions in their purest form."},{"t":"Gentle Dance Hold","d":"Put on soft music from any tradition you love and slow-dance with baby against your chest. Heartbeat, warmth, and rhythm — comfort in three languages babies already speak."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Your family’s ways are baby’s first traditions — keep them close this week.","items":["Blow a soft “fff” — family, five, fun — during playtime.","Count to five on baby’s fingers at every feeding.","Cook one family favorite with baby watching safely, and narrate it.","Sing the lullaby you grew up with at bedtime."]}},{"label":"Week 3 — Starry Nights","days":[{"day":"Monday","focus":"Night & Nap Sounds","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"N-N-Night Hum","d":"Hum a gentle “nnn” softly against baby’s hair — night, nap, nuzzle. Feeling the sound buzz while hearing it gives baby a double dose of /n/."},{"t":"Goodnight Everything","d":"At bedtime, carry baby to say goodnight to familiar things — “Goodnight lamp, goodnight chair.” Predictable rituals tell baby’s body it is safe to sleep."}]},{"day":"Tuesday","focus":"Star Shapes","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Star Hand Stretch","d":"Gently open baby’s fingers wide like a star, then curl them closed, singing “twinkle, twinkle” as you go. Little hand stretches build the muscles for grasping."},{"t":"Soft Star Reach","d":"Hold a soft star toy or a star cut from felt above baby and let those arms reach and bat (always supervise). Reaching for a target is baby’s whole workout."}]},{"day":"Wednesday","focus":"Light & Dark Play","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Peekaboo Blanket Night","d":"Drape a thin blanket briefly over your own head and ask, “Where did Mama go?” then pop out. Light, dark, gone, back — object permanence practice disguised as giggles."},{"t":"Shadow Wall Show","d":"Make slow shadow shapes on the wall with a lamp or flashlight while baby watches from your lap. Contrast and slow movement are perfect food for developing eyes."}]},{"day":"Thursday","focus":"Nighttime Traditions","domains":["Social Studies","Creative Expression"],"opts":[{"t":"World Lullaby Night","d":"Play or sing lullabies from different cultures tonight and sway along. Every tradition rocks its babies to sleep — baby is joining a very big family."},{"t":"Battery Tea-Light Song","d":"Turn on a battery tea light (never a flame near baby), dim the lights, and sing one quiet song together. Many winter traditions share this same soft glow."}]},{"day":"Friday","focus":"Starry Story Time","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Nighttime Book Nest","d":"Build a little pillow nest and read a bedtime or starry-night book in your softest voice. The routine of book-then-sleep is a gift that lasts for years."},{"t":"Star Word Everywhere","d":"Point to stars — in a book, on pajamas, out the window — and say “star” each time. Hearing one word across many places is how word meanings grow."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Quiet nights and little stars — this week glows gently.","items":["Hum “nnn” at naptime — night, nap, nuzzle.","One “goodnight everything” walk through the house before bed.","Trace a star shape on baby’s palm with your fingertip.","Read one bedtime book in the dimmest, coziest light."]}},{"label":"Week 4 — Warm Wishes for the World","days":[{"day":"Monday","focus":"Round O Sounds","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"O-O-Oh Surprise","d":"Make your mouth a big round O and say a slow, delighted “ohh” at little surprises all day. Baby will study your lips — that is exactly how sounds are learned."},{"t":"Oo-Oh Echo","d":"When baby says “oo” or “ah,” copy it exactly, then add a tiny twist — “oo-oh.” You’re having baby’s first singing lesson together."}]},{"day":"Tuesday","focus":"Giving Hands","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Your Turn, My Turn","d":"Hand baby a soft toy, say “your turn,” then hold your hand open for “my turn.” Don’t tug — just invite. The rhythm of giving starts this simply."},{"t":"Here You Go Game","d":"All day, hand things over with a warm “here you go” and a smile. Baby learns generosity by feeling it long before understanding it."}]},{"day":"Wednesday","focus":"Wrap & Unwrap","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Unwrap the Toy","d":"Loosely wrap a familiar toy in a cloth — no tape — and let baby pull it free. Cheer the discovery. Problem-solving starts with a simple “how do I get it?”"},{"t":"Bowl Surprise Lift","d":"Hide a soft toy inside a big plastic bowl with another bowl resting on top like a gift box, and help baby lift the lid — surprise. Opening things up is problem-solving baby can feel proud of."}]},{"day":"Thursday","focus":"Five Warm Wishes","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Five Wishes Count","d":"Hold up your fingers and count five warm wishes for baby — one, healthy; two, happy… ending in a big hug. Counting woven into love sticks best."},{"t":"Pat-a-Cake Five","d":"Clap baby’s hands through pat-a-cake, then finish with five little claps you count out loud. Steady beats plus numbers is a two-for-one for growing brains."}]},{"day":"Friday","focus":"Hello New Year","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Baby’s Year Book","d":"Snuggle up and page through baby’s photos from this year like a storybook — “Look how tiny. Look at you now.” You’re modeling storytelling, memory, and celebration at once."},{"t":"Around the World Read","d":"Read a board book about celebrations or families around the world, pointing at the faces and lights. Every page grows baby’s picture of a big, warm world."}]}],"homeden":{"title":"The Home Den — This Week","lead":"A season of giving, a world of warmth — little ways to share it.","items":["Make round “ohh” faces together in the mirror.","Play “your turn, my turn” with one soft toy each day.","Count five warm wishes on baby’s fingers at bedtime.","Wave and say “Happy New Year” to neighbors on a walk."]}}]},"jan":{"theme":"Winter Wonders","weeks":[{"label":"Week 1 — Cold & Cozy","days":[{"day":"Monday","focus":"Warm & Cold Touch","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Cool Spoon, Warm Sock","d":"Touch baby’s palm with a cool metal spoon, then a warm — never hot — sock fresh from the dryer, naming each: “cold… warm.” Contrast is how the senses learn (always supervise)."},{"t":"Window Weather Feel","d":"Hold baby’s hand flat against a cool window, then against your warm cheek. “Cold window, warm Mama.” Simple opposites build the brain’s filing system."}]},{"day":"Tuesday","focus":"Da-Da D Sounds","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"D-D-Da Drumbeat","d":"Tap a gentle “d-d-d” rhythm on baby’s tummy while saying d words — da-da, day, duck. Rhythmic touch makes new sounds memorable."},{"t":"Da-Da Answer Game","d":"Say “da-da-da,” then pause and wait for baby’s version. Answer whatever comes back like it’s brilliant conversation — because it is."}]},{"day":"Wednesday","focus":"Cozy Blanket Play","domains":["Approaches to Learning","Physical Development"],"opts":[{"t":"Blanket Burrito Peek","d":"Lay baby on a soft blanket and fold one edge gently over their legs, then peek — “Where are those toes? There they are.” Cozy plus peekaboo equals winter magic."},{"t":"Sock Mitten Wiggle","d":"Slip a clean, soft sock loosely over baby’s hand like a mitten and watch them work to wiggle it off (always supervise). A gentle first puzzle for a little problem-solver."}]},{"day":"Thursday","focus":"Fresh Air Minute","domains":["Physical Development","Social Studies"],"opts":[{"t":"Bundle Up Walk","d":"Bundle baby for a short stroller walk and narrate winter — bare branches, gray sky, your breath in the air if it’s cold enough. Fresh air and new sights reset fussy days."},{"t":"Neighborhood Hello Tour","d":"On your walk, wave at neighbors, dogs, and delivery trucks with a cheery “hello.” Baby’s world is bigger than the living room, and waving is how they join it."}]},{"day":"Friday","focus":"Cozy Story Corner","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Snowy Day Snuggle","d":"Read The Snowy Day or any wintry board book under a shared blanket. Warm lap plus cold pictures — baby is learning that stories can take you places."},{"t":"Rocking Chair Tales","d":"Rock together while you simply talk about your day in a soft, slow voice. Long before words, baby is soaking in the music of conversation."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Cold outside, warm together — small cozy moments for the week.","items":["Play “cold spoon, warm sock” at changing time (always supervise).","Tap a d-d-da rhythm during play — da-da, day, duck.","One short bundled-up walk, narrating the winter sky.","Read one wintry book under a shared blanket."]}},{"label":"Week 2 — Soft as Snow","days":[{"day":"Monday","focus":"P-P-Pop Sounds","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"P-Pop Lip Play","d":"Make popping “p-p-p” sounds with your lips close to baby’s ear, then far away — pat, pop, peek. Watch baby hunt for where the sound went."},{"t":"Puffy Cheek Pop","d":"Puff your cheeks up big, guide baby’s hands to pat them, and let the air pop out. Silly, yes — and a whole lesson in cause and effect and /p/."}]},{"day":"Tuesday","focus":"Snow-Soft Textures","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Cotton Cloud Touch","d":"Hold a cotton ball firmly in your own fingers and brush it gently along baby’s arm — “soft, like snow.” Keep it in your hand the whole time and never leave it with baby."},{"t":"White Towel Mountain","d":"Pile clean white towels into a soft mountain for supervised tummy-time climbing practice. Little pushes against squishy slopes build big muscles."}]},{"day":"Wednesday","focus":"Six Little Pats","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Six Pat Count","d":"Pat baby’s knees six slow times, counting out loud, then finish with a raspberry kiss. Baby is hearing number order — and mostly loving the kiss."},{"t":"Fill and Dump Cups","d":"Drop two or three large soft items into a big plastic bowl, then help baby tip it over — “all gone.” Filling and dumping is early math about empty, full, and more."}]},{"day":"Thursday","focus":"Blue Sky Watch","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Blue Blanket Sky","d":"Lie back together on a blanket — outside on a mild day or by a window — and watch the sky. Say “blue” and “clouds.” Shared looking builds shared attention, the root of learning."},{"t":"Blue Things Basket","d":"Gather three or four big, safe blue things — a sock, a cup, a washcloth — into a basket for baby to explore from your lap (always supervise). One color, many textures."}]},{"day":"Friday","focus":"Snow Songs & Stories","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Snowflake Finger Dance","d":"Wiggle your fingers down like falling snow while singing a slow “snowflakes falling” to any tune, landing with a tickle on baby’s tummy. Anticipation plus melody equals pure delight."},{"t":"Winter Picture Walk","d":"“Read” a winter book by just talking about the pictures — “Look, a red mitten.” At this age, pointing and naming is the whole curriculum."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Soft, white, and slow — a snow-inspired week, no snow required.","items":["Pop “p-p-p” sounds at play — pat, peek, pop.","Count six gentle pats on knees or toes each day.","Point out blue — the sky, jeans, a favorite cup.","Talk through the pictures of one winter book together."]}},{"label":"Week 3 — Sleepy Winter Animals","days":[{"day":"Monday","focus":"Quiet Q Time","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Quiet Whisper Game","d":"Whisper “qu-qu-quiet” and baby’s name, then watch them go still and listen. Whispers are attention magnets — and a sweet little dose of /q/."},{"t":"Hush Little Baby","d":"Sing Hush Little Baby while rocking slow as a sleepy bear. Your calm voice teaches baby’s body what settling down feels like."}]},{"day":"Tuesday","focus":"Animal Sound Play","domains":["Creative Expression","Scientific Inquiry"],"opts":[{"t":"Growl and Tweet","d":"Make gentle animal sounds — a soft bear grr, a tiny bird tweet — and pause between each so baby can react. Sound play grows listening skills."},{"t":"Sleepy Bear Cave","d":"Drape a blanket over a chair to make a dim little cave and cuddle inside for a minute like hibernating bears (always supervise). New little spaces, safe in your arms, stretch baby’s comfort zone."}]},{"day":"Wednesday","focus":"Winter Animal Moves","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Penguin Waddle Hold","d":"Hold baby upright against you and waddle side to side like a penguin, humming as you go. Gentle rhythmic movement builds the balance systems deep in the brain."},{"t":"Bunny Hop Knees","d":"Seat baby on your knees facing you and give tiny bunny-hop bounces, pausing before each round. That pause teaches anticipation — baby will tell you when to go again."}]},{"day":"Thursday","focus":"Cozy Homes","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Cozy Home Tour","d":"Carry baby room to room saying who and what lives where — “This is where we eat. This is Grandma’s chair.” Home is baby’s first map."},{"t":"Stuffed Animal Tuck-In","d":"Help baby’s hands tuck a stuffed animal under a washcloth blanket with a soft “night-night, bear.” Caring play plants the first seeds of empathy."}]},{"day":"Friday","focus":"Animal Story Nest","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Over and Under Read","d":"Share Over and Under the Snow or any animal book, adding a soft animal sound to each page. Sounds glue baby’s attention to the story."},{"t":"Mirror Animal Faces","d":"Sit with baby facing a mirror and make gentle animal faces together — sleepy bear, surprised owl. Mirrors double the fun and build self-recognition."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Snuggle in like the winter animals do — slow, warm, and close.","items":["Whisper “qu-qu-quiet” before naps — whispers work wonders.","Add one soft animal sound to every book you read.","Penguin-waddle or bunny-bounce for a giggly minute daily.","Tuck in a stuffed animal together at bedtime."]}},{"label":"Week 4 — Bright & Curious","days":[{"day":"Monday","focus":"Diamond Shapes","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Diamond Palm Trace","d":"Trace a slow diamond on baby’s palm with your fingertip, saying “diamond” as you go. Shape words plus touch plant seeds that sprout years later."},{"t":"Kite Shape Swoop","d":"Cut a big paper diamond, hold it like a kite, and swoop it slowly for baby to track and reach for — you keep hold of it the whole time. Tracking a moving target is real work for baby eyes."}]},{"day":"Tuesday","focus":"Playful Sound Review","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"D-P-Q Bounce","d":"Sing the alphabet slowly with a little knee bounce on D, P, and Q. The letters don’t matter yet — the bouncing, singing closeness does."},{"t":"Kitchen Echo Concert","d":"Sit on the kitchen floor and echo every sound baby makes, adding a gentle tap on a plastic bowl. Being copied tells baby their voice matters."}]},{"day":"Wednesday","focus":"Ice & Light Wonder","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Ice Cube Watch","d":"Seal an ice cube in a zip-top bag, keep it in your own hand, and let baby touch the cold, slippery outside for a moment — then away it goes (always supervise). Cold, wet, melting: baby’s first science lab."},{"t":"Sun Sparkle Spot","d":"Find a patch of winter sunlight on the floor and let baby play in its warmth, patting the bright spot. Noticing light and shadow is the beginning of wondering why."}]},{"day":"Thursday","focus":"Counting to Six","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Six Kisses Count","d":"Count six kisses up baby’s arm from wrist to shoulder, slow and loud. By the time counting is schoolwork, it will already feel like love."},{"t":"Growing So Big","d":"Stretch baby’s arms gently up — “so-o-o big” — then count to six on your fingers and finish with a hug. Praise, stretch, and numbers wrapped into one happy ritual."}]},{"day":"Friday","focus":"Wonder Wrap-Up","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Feelings Faces Book","d":"Read Your Feelings Matter by Mrs. Bear, making each feeling face big and slow. Naming feelings from the very start builds emotional smarts for life."},{"t":"Winter Wonders Recap","d":"Take a slow victory lap of the month — touch the cool window, wave at the sky, sing one favorite lullaby. Revisiting familiar things shows baby how much they’ve grown."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Bright eyes, big wonder — finish the month with little discoveries.","items":["Trace a diamond on baby’s palm and say the shape name.","Count six kisses up baby’s arm every morning.","Bounce on D, P, and Q in a slow alphabet song.","Let baby feel a bagged ice cube for one supervised moment."]}}]},"feb":{"theme":"Kindness & Friendship","weeks":[{"label":"Week 1 — Warm Hello Faces","days":[{"day":"Monday","focus":"Smiles & Greetings","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Mirror Hello","d":"Hold baby up to the mirror and say a warm hello to the baby looking back. Wave, smile, and name what you see — “happy eyes, big smile.” Warm faces are baby’s favorite lesson."},{"t":"Coo & Answer","d":"Lie face-to-face on a blanket and copy every coo and squeak baby makes, then pause so baby can answer. That back-and-forth is a real first conversation."}]},{"day":"Tuesday","focus":"Reach & Touch","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Pink Scarf Reach","d":"Dangle a soft pink scarf or sock just above baby during tummy time and let those little arms reach and grab (always supervise). Reaching builds the muscles friendship hugs will need."},{"t":"Texture Hello Tour","d":"Carry baby around the room to touch three soft things — a blanket, a sweater, a plush toy. Name each feel: “soft… fuzzy… smooth.” Touch is how babies study the world."}]},{"day":"Wednesday","focus":"Sound of R","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Rrr Rock-a-Bye","d":"Rock baby in your arms and playfully roll the sound — “rrr-rock, rrr-rock.” No flashcards needed; hearing sounds in a loving voice is exactly how letters begin."},{"t":"Rattle Talk","d":"Shake a rattle to one side, pause, and wait for baby to turn or wiggle before shaking again. You’re teaching listening — and taking turns like a friend."}]},{"day":"Thursday","focus":"Counting Kisses","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Seven Little Kisses","d":"Kiss up baby’s arm and count each one out loud, all the way to seven — this month’s number. Numbers heard in happy moments stick best."},{"t":"This Little Toe","d":"Count baby’s toes with a gentle wiggle for each number, and pause on the last toe for a tickle. Anticipation is baby’s first pattern."}]},{"day":"Friday","focus":"My Special People","domains":["Social Studies","Approaches to Learning"],"opts":[{"t":"Friends Who Love You","d":"Look at photos of family and friends together — a cousin, a neighbor, a playgroup buddy — and name each person slowly. Learning the faces of their people is a baby’s very first social studies."},{"t":"Friendship Story Snuggle","d":"Cuddle up with any picture book about friends and point to the faces on each page. Lap reading builds attention, vocabulary, and a lifelong love of books."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Pop these in the diaper bag — friendship starts in your arms.","items":["Say hello to baby by name every morning — greetings teach belonging.","Copy one coo a day, then wait for the answer back.","Kiss and count to seven up a little arm at bedtime.","Hum the rrr sound into a snuggle — “rrr-rock-a-bye.”"]}},{"label":"Week 2 — Gentle Hands","days":[{"day":"Monday","focus":"Soft & Gentle","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Soft Things Basket","d":"Fill a laundry basket with soft fabrics — fleece, a clean sock, a knit hat — and let baby grasp and explore each one (always supervise). Different textures build curious little hands."},{"t":"Gentle Pat Practice","d":"Guide baby’s hand to pat a stuffed animal slowly while you say “gentle, gentle.” Babies learn softness from your hands before your words."}]},{"day":"Tuesday","focus":"Hands That Clap","domains":["Creative Expression","Physical Development"],"opts":[{"t":"Slow Pat-a-Cake","d":"Hold baby’s hands and play pat-a-cake at half speed, ending in a big stretch up high. Clapping games build rhythm and body control at the same time."},{"t":"Kitchen Drum Duo","d":"Turn a plastic bowl upside down, tap a soft beat, then help baby’s hand tap along. Making sound together is baby’s first band."}]},{"day":"Wednesday","focus":"Sound of U","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Uh-Oh Game","d":"Drop a soft toy off your lap dramatically and say “uh-oh!” Then hand it back and wait — most babies want the game again and again. That “uh” is the letter U saying hello."},{"t":"Up-Up-Up Song","d":"Lift baby slowly while singing “up, up, up,” then float back down with a long “dowwwn.” Word plus motion is how meaning sinks in."}]},{"day":"Thursday","focus":"Little Helpers","domains":["Social Studies","Approaches to Learning"],"opts":[{"t":"Tidy-Up Song","d":"Sing a little “clean-up, clean-up” tune while you tidy toys, handing baby one soft toy to hold until it goes in the basket last. Songs turn family jobs into games."},{"t":"Thank the Helpers","d":"When the mail carrier or a neighbor passes, wave together and say a warm thank-you out loud. Friendly thank-yous are baby’s first lesson in community kindness."}]},{"day":"Friday","focus":"Ten Little Fingers","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Finger Count Cuddle","d":"Count baby’s fingers one by one during a cuddle, giving each a tiny squeeze. Counting the same cozy way every day builds a comforting pattern."},{"t":"Ask for More","d":"Give one kiss, pause, and ask “more?” while making the baby sign for more — fingertips tapping together. Signs give baby a voice before words come."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tape this to the fridge — gentle hands grow from gentle days.","items":["Say “gentle” while you stroke baby’s arm — pair the word with the feel.","Let baby hold a clean sock while you fold laundry together.","Play one round of slow pat-a-cake at diaper changes.","Try the baby sign for “more” — fingertips tapping together."]}},{"label":"Week 3 — Songs of Love","days":[{"day":"Monday","focus":"Lap Song Time","domains":["Creative Expression","Social & Emotional Development"],"opts":[{"t":"Skidamarink Serenade","d":"Sing “Skidamarink” with big arm motions, ending with a hug on “I love you.” Babies feel the meaning of love songs long before the words."},{"t":"Sunshine Sway","d":"Slow-dance around the room to “You Are My Sunshine,” cheek to cheek. Gentle rhythm and your heartbeat are deeply calming."}]},{"day":"Tuesday","focus":"Bounce & Rhyme","domains":["Physical Development","Language & Literacy"],"opts":[{"t":"Knee Bounce Rhymes","d":"Bounce baby gently on your knees to a steady rhyme, slowing down and speeding up. Rhythm felt in the body becomes rhythm heard in words."},{"t":"See-Saw Sweetheart","d":"Hold baby’s hands and gently see-saw forward and back to a slow “see-saw, up and down” chant. That easy rocking builds trunk strength for sitting."}]},{"day":"Wednesday","focus":"Sound of V","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Vvv Buzzy Lips","d":"Make a soft “vvv” against baby’s palm so they feel the buzz, then watch them study your mouth. Feeling a sound is science and phonics in one."},{"t":"Voice or Quiet","d":"Sing a line, then go silent and still; start again when baby wiggles. Baby is learning cause and effect — my wiggle brings the music back."}]},{"day":"Thursday","focus":"Quiet Cuddle Songs","domains":["Social & Emotional Development","Approaches to Learning"],"opts":[{"t":"Hum & Hold","d":"Hum a lullaby with baby’s head resting on your chest so they feel it rumble. The vibration plus your warmth says all is well."},{"t":"Sing the Story","d":"Open a favorite picture book and sing the words to any tune while pointing at the pictures. Melody holds baby’s attention and makes books feel like joy."}]},{"day":"Friday","focus":"Family Song Traditions","domains":["Social Studies","Mathematical Thinking"],"opts":[{"t":"Grandma’s Song","d":"Sing a song from your own childhood or family language and tell baby who sang it to you. Family songs pass belonging down a generation."},{"t":"Five Little Ducks","d":"Sing “Five Little Ducks” on your fingers, folding one down each verse. Counting songs are math babies can hear — and cuddle to."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Little songs, big love — keep these tunes in your pocket.","items":["End “Skidamarink” with a hug every single time — babies love the ritual.","Hum with baby’s head on your chest so they feel the song.","Slip baby’s name into one song a day.","Sing “Five Little Ducks” on your fingers at bath time."]}},{"label":"Week 4 — Hearts & Hugs","days":[{"day":"Monday","focus":"Pink & Red","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Pink Peekaboo","d":"Play peekaboo behind a pink or red cloth, letting baby pull it away from your face. Peekaboo teaches that loved ones come back — big comfort in a little game."},{"t":"Color Spot Carry","d":"Carry baby around the house pointing out pink and red things — a mug, a shirt, a blanket. Naming colors now builds the words for later."}]},{"day":"Tuesday","focus":"Heart Shapes","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Heart Pillow Tummy Time","d":"Prop baby on a heart-shaped pillow — or any soft pillow — for tummy time with a toy just out of reach (always supervise). Shape talk plus a strong little neck."},{"t":"Trace a Heart","d":"Draw a big heart on paper and slowly trace it with baby’s finger while saying “around and down.” Feeling a shape comes before knowing it."}]},{"day":"Wednesday","focus":"Hugs & Squeezes","domains":["Social & Emotional Development","Physical Development"],"opts":[{"t":"Squeeze & Release","d":"Give a slow, gentle squeeze-hug, release, and wait for baby to lean back in. Letting baby ask again teaches that affection is a two-way street."},{"t":"Teddy Hug Show","d":"Hug a teddy bear warmly, say “hug,” then offer the teddy to baby. Babies learn kindness by watching you give it."}]},{"day":"Thursday","focus":"Kind Words","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Love Whispers","d":"Whisper three kind things in baby’s ear — “you are loved, you are safe, you are my joy.” Tone lands long before vocabulary."},{"t":"Feelings Book Time","d":"Snuggle up with Your Feelings Matter — Mrs. Bear’s own book — and name each feeling face you see, then make the face together. Naming feelings is the seed of empathy."}]},{"day":"Friday","focus":"Sharing the Love","domains":["Creative Expression","Social Studies"],"opts":[{"t":"Family Love Parade","d":"Video-call or visit a grandparent and help baby wave and blow a kiss. Sharing love with their circle of people widens baby’s world."},{"t":"Dance of Hearts","d":"Put on a favorite love song and sway with baby, dipping gently on the long notes. Dancing together is creative expression baby can feel head to toe."}]}],"homeden":{"title":"The Home Den — This Week","lead":"One more week of hearts — send the love home.","items":["Whisper one kind thing at every diaper change.","Play peekaboo with a pink washcloth at bath time.","Trace a heart on baby’s back before sleep.","Hug a teddy, say “hug,” and offer it to baby to copy."]}}]},"mar":{"theme":"Things That Grow","weeks":[{"label":"Week 1 — Tiny Seeds & Sprouts","days":[{"day":"Monday","focus":"Planting Together","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Watch the Seed Cup","d":"Plant a seed in a cup, set it on the windowsill, and visit it with baby every morning — “still sleeping… still growing.” Baby won’t remember the seed, but they’ll feel your wonder."},{"t":"Dirt-Free Digging","d":"Let baby rake little fingers through a tray of big crumpled brown paper “soil” while you narrate digging and planting. Use big pieces only and trade out any that tear — paper heads for mouths fast (always supervise)."}]},{"day":"Tuesday","focus":"Sound of I","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Iii Grow Song","d":"Stretch the long-I sound as you lift baby slowly toward the ceiling — “we grow hiiigh.” Bear Phonics starts with sounds in songs, and your lap is the classroom."},{"t":"I See You","d":"Play “I see…” around the room — “I see the lamp, I see the window, I see YOU.” The long-I gets a workout, and baby learns words follow your point."}]},{"day":"Wednesday","focus":"Stretch & Grow","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Sprout Stretches","d":"Curl baby’s arms in close like a little seed, then stretch them up slowly like a sprout reaching for sun. Repeat until the giggles come."},{"t":"Reach for the Sun","d":"Hold a soft yellow toy just above baby during floor play and let them reach, roll, and work for it (always supervise). Effort is a habit that starts now."}]},{"day":"Thursday","focus":"Counting Seeds","domains":["Mathematical Thinking","Language & Literacy"],"opts":[{"t":"Eight Little Pats","d":"Pat baby’s tummy gently eight times, counting out loud, then start over. Eight is this month’s number, and rhythm makes it musical."},{"t":"Seed Story Time","d":"Read The Tiny Seed or any garden picture book, letting baby pat the pages. Books plus laps grow readers."}]},{"day":"Friday","focus":"Growers Around Us","domains":["Social Studies","Creative Expression"],"opts":[{"t":"Wave to the Garden","d":"Visit a garden, a farm stand, or a neighbor’s flower pot and name who takes care of it — “the farmer grows our food.” Baby’s community includes the people who help things grow."},{"t":"Flower Color Show","d":"Gather a purple flower, a green leaf, and a white petal and hold each up for baby to study. Nature is baby’s first art gallery."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tuck these in the diaper bag — you’re growing a grower.","items":["Plant one seed in a cup and greet it with baby each morning.","Do seed-to-sprout stretches after diaper changes.","Count eight gentle tummy pats at bedtime.","Stretch the “iii” sound into a lift — “we grow hiiigh.”"]}},{"label":"Week 2 — Green Leaves & Grass","days":[{"day":"Monday","focus":"Grass Under Us","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Barefoot Grass Time","d":"Spread a blanket at the grass’s edge and let baby’s bare feet brush the blades (always supervise). New textures on little feet wake up the senses."},{"t":"Herb Sniff Hello","d":"Hold a sprig of a soft kitchen herb — mint or basil — in your own hand and let baby lean in for a slow sniff while you say “green.” Smell is a sense we often forget to feed."}]},{"day":"Tuesday","focus":"Green Everywhere","domains":["Approaches to Learning","Language & Literacy"],"opts":[{"t":"Green Tour","d":"Walk the house or yard naming green things — “green leaf, green towel, green cup.” Repeating one color all day builds the idea of color itself."},{"t":"Green Book Look","d":"Cuddle up with Planting a Rainbow or any leafy picture book and point to every green thing. Pointing together turns pages into conversation."}]},{"day":"Wednesday","focus":"Sound of X","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Ks-Ks Kisses","d":"Play with the /ks/ sound X makes — “a kiss for the fox, ks-ks” — landing a kiss on baby’s cheek each time. Silly sounds in a warm voice are real phonics for babies."},{"t":"Box Drum Beat","d":"Tap a slow beat on a cardboard box, saying “b-o-x,” then help baby’s hand tap too. Sound play and rhythm in one free instrument."}]},{"day":"Thursday","focus":"Growing Song Time","domains":["Creative Expression","Social & Emotional Development"],"opts":[{"t":"Green Grass Song","d":"Sing “The Green Grass Grew All Around” with a sway that gets a little bigger each verse. Growing songs match this month’s magic."},{"t":"Sunshine Snuggle","d":"Rock and sing “You Are My Sunshine” by the window in the morning light. Sunshine helps things grow — babies included."}]},{"day":"Friday","focus":"Leaves & Numbers","domains":["Mathematical Thinking","Social Studies"],"opts":[{"t":"Count the Leaves","d":"Line up eight big leaves on the blanket and count them out loud, handing baby one to hold. Numbers plus nature is a happy pair."},{"t":"Neighborhood Green Walk","d":"Stroll the neighborhood pointing out gardens and trees your neighbors care for. Baby is learning their community, one wave at a time."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Green week at school — bring the outside in at home.","items":["Let baby’s bare feet feel real grass for one minute (stay close).","Hand over one big clean leaf to crinkle — trade it before it tears.","Name three green things on every walk.","Sing a growing song with a sway that grows bigger too."]}},{"label":"Week 3 — Baby Animals Grow","days":[{"day":"Monday","focus":"Animal Friends","domains":["Social & Emotional Development","Creative Expression"],"opts":[{"t":"Soft Animal Parade","d":"March baby’s stuffed animals across the blanket one at a time, naming each baby animal — “little lamb, little chick.” Then let baby choose one to cuddle."},{"t":"Animal Voice Show","d":"Make one gentle animal sound at a time — moo, baa, peep — and pause for baby’s reaction before the next. Funny sounds teach careful listening."}]},{"day":"Tuesday","focus":"Move Like Animals","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Bunny Bounce Laps","d":"Bounce baby softly on your lap like a baby bunny, then rock slow and heavy like a sleepy bear. Changing tempo builds body awareness."},{"t":"Tummy-Time Turtle","d":"Get down on the floor face-to-face for tummy time and be two slow turtles together. Company makes tummy time last longer."}]},{"day":"Wednesday","focus":"Sound of Z","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Zzz Bee Fly","d":"Fly your finger like a little bee — “zzzzz” — landing gently on baby’s tummy. Baby tracks the sound and the touch, and Z gets its moment."},{"t":"Sleepy Zzz Game","d":"Pretend to snore “zzz,” startle awake with a big smile, and repeat. Babies love predictable surprises — that’s how they test what they know."}]},{"day":"Thursday","focus":"Mamas & Babies","domains":["Social Studies","Mathematical Thinking"],"opts":[{"t":"Big & Little Match","d":"Show pairs side by side — your sock and baby’s sock, your shoe and theirs — saying “big… little.” Comparing sizes is early math baby can see."},{"t":"Animal Family Book","d":"Read any baby-animal book and name the mama and her baby on each page. Families come in every species, and baby is learning theirs."}]},{"day":"Friday","focus":"Little Nest Time","domains":["Social & Emotional Development","Physical Development"],"opts":[{"t":"Two Birds, One Nest","d":"Build a soft blanket nest on the floor and settle in like two birds, humming quietly. Cozy containment feels like a hug all around."},{"t":"Fly Home Little Bird","d":"Lift baby gently overhead like a bird — “flying home to the nest” — then land softly in a hug. Movement with a safe landing builds trust."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Baby-animal week — you’re the mama bear of the den.","items":["Make one animal sound and wait for baby’s face to answer.","Match big and little socks side by side — “big… little.”","Buzz a “zzz” finger-bee to a soft tummy landing.","Read one baby-animal book, naming each mama and baby."]}},{"label":"Week 4 — Watch Me Grow","days":[{"day":"Monday","focus":"Look How Big","domains":["Social & Emotional Development","Mathematical Thinking"],"opts":[{"t":"So Big Game","d":"Ask “how big is baby?” and stretch those arms up — “sooo big.” A classic for a reason; it celebrates growing every single time."},{"t":"Growth Chart Start","d":"Lay baby on a paper strip, mark their length, and tape it to the wall. Mark again next month — watching the marks climb never gets old."}]},{"day":"Tuesday","focus":"Strong Little Bodies","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Pillow Mountain Roll","d":"Lay a firm pillow under a blanket and help baby roll or scoot over the little hill (always supervise). Tiny challenges grow strong movers."},{"t":"Sit & Steady","d":"Sit baby between your legs with your hands hovering close and let them balance a beat on their own. Your nearby hands are the best safety net."}]},{"day":"Wednesday","focus":"Sounds We Know","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Sound Parade Review","d":"Sing this month’s sounds back in one silly ride — “iii grow high, ks-ks kiss, zzz sleepy bee.” Review disguised as play is the infant way."},{"t":"Echo and Add","d":"Whatever baby babbles, echo it back exactly, then add one tiny twist of your own. You’re showing them their voice moves the world."}]},{"day":"Thursday","focus":"Oval & Purple","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Trace the Oval","d":"Draw a big purple oval and trace it slowly with baby’s finger — “rounnnd like an egg.” Shapes start as a feeling under the finger."},{"t":"Purple Light Play","d":"Drape a sheer purple scarf over a flashlight in a dim room and watch the soft glow together (always supervise). Light and color are baby’s favorite science."}]},{"day":"Friday","focus":"Celebrate Growing","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Then & Now Photos","d":"Look at baby’s newborn photos together and tell the story — “you were so tiny, and look at you now.” Family stories are how babies learn they belong."},{"t":"Growing Book Cuddle","d":"End the month with a snuggly read — The Tiny Seed or any favorite — and whisper “you’re growing too.” Books at bedtime plant the reading habit early."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Last week of the growing month — look how far you’ve both come.","items":["Play “so big” at every wake-up this week.","Mark baby’s length on a paper strip and date it.","Echo one babble back, then add a tiny twist.","Shine a flashlight through a purple scarf at dusk (stay close)."]}}]},"apr":{"theme":"Our Big Blue Earth","weeks":[{"label":"Week 1 — Wonderful Water","days":[{"day":"Monday","focus":"Water Wonders","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Splash Hands Bowl","d":"Sit baby on your lap at a shallow bowl of warm water and let those hands splash, always within arm’s reach. Water is baby’s first physics lab."},{"t":"Sponge Squeeze Show","d":"Squeeze a wet sponge slowly so baby watches the drips fall, then guide their hand to try. Cause and effect, one drip at a time."}]},{"day":"Tuesday","focus":"Sound of Y","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Yay for You","d":"Cheer a gentle “yaaay” with baby’s hands in yours after every little win — a roll, a reach, a smile. April’s /y/ sound rides in on celebration."},{"t":"Yes-Yes Song","d":"Sing a made-up “yes, yes, yes” song while nodding big and slow. Babies read your nod long before they know the word."}]},{"day":"Wednesday","focus":"Blue World Look","domains":["Approaches to Learning","Social Studies"],"opts":[{"t":"Blue Things Tour","d":"Carry baby through the house finding blue — a towel, a bowl, the sky out the window. One color, said many ways, starts the color words."},{"t":"Window Weather Watch","d":"Sit at the window and narrate the world going by — “rain for the flowers, clouds moving, a neighbor watering.” Baby’s community starts at the glass."}]},{"day":"Thursday","focus":"Count the Drops","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Nine Little Drips","d":"Drip nine warm drops onto baby’s toes at bath time, counting each one. Nine is April’s number, and bath giggles make it stick."},{"t":"Rain Sound Cuddle","d":"Cuddle up and listen to real rain — or a soft “shhh” you make — rocking to its rhythm. Calm listening together is emotional gold."}]},{"day":"Friday","focus":"Water Stories","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"After-Bath Book","d":"Bring a sturdy board book about water, fish, or boats to your lap right after bath. Warm, clean, and cozy is prime reading time."},{"t":"Float or Sink Show","d":"In a shallow basin, float a plastic cup, then add a wet washcloth that slowly sinks, narrating what happens (always within arm’s reach). Baby’s eyes are taking notes."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Splash week — keep a towel close and these ideas closer.","items":["Count nine drips on tiny toes at every bath.","Let baby splash a shallow bowl on your lap — never step away.","Cheer “yaaay” with baby’s hands after every little win.","Read one book right after bath while baby is warm and calm."]}},{"label":"Week 2 — Trees & Green Places","days":[{"day":"Monday","focus":"Under a Tree","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Leaf Light Watching","d":"Lie on a blanket under a tree with baby on your chest and watch the leaves move against the sky. Dappled light is endlessly interesting to young eyes."},{"t":"Bark Touch Walk","d":"Guide baby’s palm along tree bark, a smooth leaf, and your soft sleeve — “rough… smooth… soft.” Contrast is what teaches."}]},{"day":"Tuesday","focus":"Strong Like Trees","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Tall Tree Stretch","d":"Hold baby facing out and grow tall together — reach up, then sway side to side like branches in the wind. Gentle swaying builds balance."},{"t":"Log Roll Play","d":"Help baby roll slowly across a soft blanket like a rolling log, cheering each turn. Rolling is a big gross-motor milestone worth celebrating."}]},{"day":"Wednesday","focus":"Green & Teal","domains":["Creative Expression","Scientific Inquiry"],"opts":[{"t":"Teal Scarf Float","d":"Toss a teal or blue-green scarf above baby and let it drift down slowly. Tracking a falling scarf builds eye muscles and wonder."},{"t":"Earth Color Tray","d":"Set a green leaf, a teal cloth, and a big blue lid on a tray for baby to study and grasp (always supervise). A tiny museum of Earth’s colors."}]},{"day":"Thursday","focus":"Tree Friends","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Bird Watch Chat","d":"Watch for birds from the stroller or window and give each one a running commentary — “hello, red bird, off to your nest.” Rich talk now means big vocabulary later."},{"t":"Park People Wave","d":"At the park, name what people are doing — “kids climbing, a helper raking leaves” — and wave together. The park is baby’s town square."}]},{"day":"Friday","focus":"Counting in Nature","domains":["Mathematical Thinking","Language & Literacy"],"opts":[{"t":"Nine Leaf Line","d":"Line up nine leaves on the blanket, counting as you go, then let baby scatter them — the best part. Count again if the giggles ask for it."},{"t":"Tree Book Lap Time","d":"Read any tree or forest picture book, patting the trunk pictures together. Books under a real tree make a core memory in the making."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Take the week outside — the trees are waiting.","items":["Spend five minutes on a blanket under a tree, just watching.","Touch bark, leaf, and sleeve — “rough, smooth, soft.”","Sway like branches while holding baby facing out.","Count nine leaves, then let baby scatter the pile."]}},{"label":"Week 3 — Sky & Moon","days":[{"day":"Monday","focus":"Cloud Watching","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Sky Show Blanket","d":"Lie back with baby on your chest and watch the clouds drift, narrating the shapes you see. Shared attention on one thing is the root of all learning."},{"t":"Breeze on Skin","d":"Step outside on a breezy moment and let the wind brush baby’s cheeks — “the wind says hello.” Weather is a full-body sensory story."}]},{"day":"Tuesday","focus":"Crescent Moon","domains":["Mathematical Thinking","Language & Literacy"],"opts":[{"t":"Moon Shape Trace","d":"Draw a big crescent moon and glide baby’s finger along its curve — “curved like a banana.” April’s shape, felt before it’s known."},{"t":"Goodnight Moon Time","d":"Read Goodnight Moon or any bedtime book, pointing at the moon on each page. Naming the same moon every night builds word memory."}]},{"day":"Wednesday","focus":"Up So High","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Airplane Glide","d":"Lie on your back, rest baby’s tummy on your shins, and glide them gently like a little plane, holding hands the whole time. Core strength for both of you."},{"t":"Sky Song Sway","d":"Sway with baby to a gentle “up in the sky” tune you make up on the spot, lifting slightly on the high notes. Music you invent is baby’s favorite album."}]},{"day":"Thursday","focus":"Day & Night","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Flashlight Stars","d":"In a dim room, drift a flashlight beam slowly across the ceiling like a wandering star (always supervise). Calm light play makes a lovely wind-down."},{"t":"Sun Up Hello","d":"Open the curtains together each morning and greet the day — “good morning, sun.” Predictable little rituals tell baby the world is safe."}]},{"day":"Friday","focus":"Our Neighborhood Sky","domains":["Social Studies","Creative Expression"],"opts":[{"t":"Sunset Stroll Wave","d":"Take an early-evening stroller walk, waving to neighbors while pointing out the changing sky colors. Baby’s world is people plus sky."},{"t":"Twinkle Lap Concert","d":"Sing “Twinkle, Twinkle, Little Star” with baby’s hands opening and closing like little stars. Hand motions plus melody is a whole-brain duet."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Eyes up this week — the sky is the classroom.","items":["Watch clouds from a blanket for a few quiet minutes.","Trace a crescent moon with baby’s finger — “curved like a banana.”","Greet the sun each morning as you open the curtains.","Sing “Twinkle, Twinkle” with opening-and-closing star hands."]}},{"label":"Week 4 — We Care for Our Earth","days":[{"day":"Monday","focus":"Gentle With Earth","domains":["Social & Emotional Development","Scientific Inquiry"],"opts":[{"t":"Gentle Flower Touch","d":"Help baby touch a flower with one soft finger — “gentle with growing things.” The word “gentle” works for petals and people alike."},{"t":"Watering Helper","d":"Hold baby while you water a plant, letting them watch the pour and pat the damp soil once (wash hands after). Caring for something small starts early."}]},{"day":"Tuesday","focus":"Sounds of Earth","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Listen Walk","d":"Take a slow walk and name each sound you catch — birds, wind, a dog, a far-off truck. Labeling sounds sharpens listening for language."},{"t":"Y Sound Encore","d":"Bring back April’s sound in one happy chant — “yes, yaaay, you.” Sounds come back best when they ride inside joy."}]},{"day":"Wednesday","focus":"Reuse & Play","domains":["Creative Expression","Physical Development"],"opts":[{"t":"Box Tunnel Peek","d":"Open both ends of a big cardboard box and play peekaboo through the tunnel — or let a crawler venture partway in (always supervise). The best toys are free."},{"t":"Crinkle Paper Band","d":"Give baby a sheet of clean packing paper to crinkle, wave, and drum while you keep it away from the mouth. A recycled rhythm section."}]},{"day":"Thursday","focus":"Earth Colors Count","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Blue-Green Sort Show","d":"Sort a pile of blue and green cloths into two stacks while baby watches, naming each one — then let baby topple both. Sorting is math theater."},{"t":"Nine Pat Goodbye","d":"Pat the grass or the rug nine times together, counting the month’s number one last time. Repetition is how nine becomes an old friend."}]},{"day":"Friday","focus":"Love Your World","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Earth Book Snuggle","d":"Close the month with The Earth Book or any nature story, naming water, trees, and sky as you go. You’ve shown baby the whole wide world this month."},{"t":"Thank-You Walk","d":"Walk the neighborhood saying small thank-yous — “thank you, tree, for shade; thank you, helper, for clean streets.” Gratitude is caught, not taught."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Little Earth-keepers start in your arms — send the love outside.","items":["Touch one flower with one gentle finger every day.","Let baby watch you water a plant and pat the soil once.","Turn a big box into a peekaboo tunnel.","End the month with an Earth book and a thank-you walk."]}}]},"may":{"theme":"On the Move","weeks":[{"label":"Week 1 — Wiggle & Reach","days":[{"day":"Monday","focus":"Tummy & Stretch","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Blanket Reach","d":"Lay baby on a blanket for tummy time and set a soft toy just past their fingertips. Cheer every stretch and scoot — each reach builds the muscles crawling needs (always supervise)."},{"t":"Scarf Dangle","d":"Hold a soft scarf just above baby's hands and let them bat and grab at it. Move it a little left, then right, so both arms get a turn."}]},{"day":"Tuesday","focus":"Lap Song Rides","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Row the Boat","d":"Sit baby on your lap, hold their hands, and rock gently while singing “Row, Row, Row Your Boat.” Rhythm plus your voice is language learning in its coziest form."},{"t":"ABC Sway","d":"Cuddle baby close and sway side to side while you softly sing the alphabet. At this age letters are just lovely sounds — your singing is the whole lesson."}]},{"day":"Wednesday","focus":"Feel & Find","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Textures Roll By","d":"During floor play, slide a soft sock, a smooth cup, and a nubby towel one at a time under baby's busy hands and feet, naming each feel. On-the-move babies learn the world skin-first (always supervise)."},{"t":"Kick and Watch","d":"Lay baby on their back and hold a light blanket above their feet so every kick makes it ripple. Cause and effect starts right at the toes."}]},{"day":"Thursday","focus":"Counting Toes","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Ten Toe Count","d":"Count baby's toes out loud, one gentle squeeze per number, all the way to this month's number ten. Numbers land best when they arrive wrapped in giggles."},{"t":"Piggies On the Go","d":"Play “This Little Piggy” on baby's toes, sending each piggy somewhere that goes — to the bus, to the train, to the big red truck — and pause before the wee-wee-wee ride home. A travel twist keeps favorite rhymes fresh."}]},{"day":"Friday","focus":"Hello & Goodbye","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Wave Practice","d":"Wave hello and bye-bye at doorways all day — to Daddy, the dog, the mail truck outside. Waving is baby's very first way of greeting their world."},{"t":"Lap Story Snuggle","d":"End the week with a board book on your lap. Point to the pictures and name what you see — reading together is bonding, no finishing the book required."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tuck these in the diaper bag — little stretches, big smiles.","items":["Do one tummy-time reach session on a blanket each day; even five minutes counts.","Sing the same lap song at every diaper change — repetition builds memory.","Count ten toes at bath time to sneak in this month's number.","Keep a board book by the rocker for a one-page snuggle read each night."]}},{"label":"Week 2 — Roll & Rock","days":[{"day":"Monday","focus":"Rolling Practice","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Roll to the Toy","d":"Lay baby on their back and hold a favorite toy off to one side to tempt a slow roll. Celebrate half-rolls too — the trying is the real win (always supervise)."},{"t":"Rocking Chair Ride","d":"Rock together in a chair or in your arms, slow and then a touch quicker, saying “slooow… quick.” Feeling speeds change builds body awareness."}]},{"day":"Tuesday","focus":"Up High Sounds","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Up High, Down Low","d":"Say “up hiiigh” as you lift baby gently in your arms and “down looow” as you lower them. This month's Bear Phonics long-I sound becomes a whole-body game."},{"t":"Hum and Rock","d":"Hold baby cheek to cheek and hum a slow tune while you sway. Babies feel your humming as much as they hear it — it is deeply calming for you both."}]},{"day":"Wednesday","focus":"Mirror Moves","domains":["Social & Emotional Development","Scientific Inquiry"],"opts":[{"t":"Mirror Rock-a-Bye","d":"Rock and sway with baby in front of a mirror so they can watch the two of you move. Seeing your faces together builds connection and self-discovery at once."},{"t":"Watch Us Move","d":"Hold baby at the mirror and wave their hand, kick those feet, and add a little bounce, naming each move — “waving… kicking… bouncing.” Watching themselves move is how babies discover “me.”"}]},{"day":"Thursday","focus":"Rocking Rhythms","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"One-Two Rock","d":"Rock baby to a steady one-two, one-two chant. A repeating beat is baby's first pattern — real math thinking, delivered as a cuddle."},{"t":"Ball Roll Count","d":"Sit with baby supported between your legs and slowly roll a soft ball away and back, counting each roll toward ten. Tracking that ball is a workout for eyes and attention."}]},{"day":"Friday","focus":"Family & Stories","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Name the Family","d":"Sit with baby and look at family photos, naming each person warmly — “Grandma… Uncle Joe.” Familiar faces are baby's first lesson in who their people are."},{"t":"Storytime Sway","d":"Rock gently while you share “Your Feelings Matter” or any favorite picture book. The swaying plus your reading voice makes story words extra soothing."}]}],"homeden":{"title":"The Home Den — This Week","lead":"A rocking, rolling week — here are four easy ways to keep it going at home.","items":["Offer a toy slightly to the side during floor play to invite rolling practice.","Rock to a steady one-two chant before naps — pattern and comfort in one.","Spend one minute a day making faces together in the mirror.","Point out family photos by name during carries around the house."]}},{"label":"Week 3 — Things That Go","days":[{"day":"Monday","focus":"Vroom & Zoom","domains":["Scientific Inquiry","Language & Literacy"],"opts":[{"t":"Soft Car Push","d":"Roll a soft toy vehicle slowly across the floor in front of baby, saying “vrooom.” Watching it travel and hearing the sound builds tracking and listening together."},{"t":"Beep and Choo","d":"Narrate the day in vehicle sounds — “beep beep” at the door, “choo choo” down the hall. Playful sounds like these are stepping stones to real words."}]},{"day":"Tuesday","focus":"Wheels & Motions","domains":["Creative Expression","Physical Development"],"opts":[{"t":"Wheels on the Bus","d":"Sing “The Wheels on the Bus” while gently moving baby's arms round and round and wipers swish-swish. Song motions wire music and movement together."},{"t":"Bicycle Legs","d":"Lay baby on their back and gently cycle their legs like pedals while you hum a riding tune. It strengthens tummy muscles and often brings on the giggles."}]},{"day":"Wednesday","focus":"Watch It Move","domains":["Approaches to Learning","Scientific Inquiry"],"opts":[{"t":"Window Traffic Watch","d":"Sit by a window and watch what goes by, narrating softly — “a big truck… a fast bike.” Following moving things stretches baby's attention span."},{"t":"Cushion Ramp Roll","d":"Lean a couch cushion into a gentle ramp and let a soft ball roll down while baby tracks it. Down it goes, every time — baby is learning how the world works."}]},{"day":"Thursday","focus":"Go & Stop","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Go-Go-Stop Ride","d":"Carry baby around the room chanting “go, go, go…” then pause dramatically on “stop.” Waiting for the next go teaches anticipation, and the payoff is pure joy."},{"t":"Ten Step March","d":"March baby around the house in your arms, counting each step out loud up to ten. Steady counting with movement lets baby feel the numbers, not just hear them."}]},{"day":"Friday","focus":"Out & About","domains":["Social Studies","Physical Development"],"opts":[{"t":"Stroller Safari","d":"Take a slow stroller ride and name everything that goes — the mail truck, a dog, a bus. Baby is meeting the neighborhood one friendly sight at a time."},{"t":"Truck Book Time","d":"Share a things-that-go picture book like “Little Blue Truck,” letting baby pat the pages. Books about wheels are a favorite first love for movers and shakers."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Everything goes this week — here is how to bring the ride home.","items":["Narrate vehicle sounds on every car ride — beep, vroom, zoom.","Play go-go-stop during hallway carries once a day.","Watch out the window together for two minutes and name what passes.","Add one wheels or truck book to bedtime this week."]}},{"label":"Week 4 — Bounce & Glide","days":[{"day":"Monday","focus":"Bouncing Rhythms","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Knee Bounce Pony","d":"Sit baby on your knees facing you and bounce gently to a pony-ride rhyme, holding them securely. Bouncing builds trunk strength and a love of rhythm at once."},{"t":"Cheek-to-Cheek Dance","d":"Put on a favorite slow song and dance around the room with baby snuggled close. Gliding to music together is movement, music, and bonding in one."}]},{"day":"Tuesday","focus":"Light & Bright","domains":["Scientific Inquiry","Language & Literacy"],"opts":[{"t":"Flashlight Glide","d":"Dim the room and slide a flashlight beam slowly along the wall while baby tracks it. Say “light… bright…” as it glides — a gentle echo of this month's long-I sound (always supervise)."},{"t":"Rainbow Scarf Glide","d":"Float colorful scarves through the air one at a time, naming each color as it drifts down. A whole rainbow, delivered in slow motion for little eyes."}]},{"day":"Wednesday","focus":"Up & Over","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Swoop and Soar","d":"Hold baby securely tummy-down along your forearms and glide slowly around the room. That gentle swooping builds head and trunk control while feeling like pure fun."},{"t":"Pillow Hill Climb","d":"Place a firm pillow under baby's tummy so they can reach up and over toward a toy. Tiny climbs like this are the very beginning of big movement (always supervise)."}]},{"day":"Thursday","focus":"Ten Little Bounces","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Count-to-Ten Bounce","d":"Give ten gentle knee bounces, counting each one out loud, then finish with a big hug at ten. Baby learns that numbers climb toward something wonderful."},{"t":"More Bounces, Please","d":"After a round of bounces, pause and show the baby sign for “more” — fingertips tapped together. Signs give baby a voice months before words arrive."}]},{"day":"Friday","focus":"Moving Together","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Around-Town Talk","d":"On your next errand, narrate the community for baby — “the bus is going, the light turned green, people are walking.” The wide world makes wonderful conversation."},{"t":"Goodnight Glide Read","d":"Close the month with a slow rocking read of any favorite book about going and doing. Your voice winding down tells baby's body the day is done."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Bounces, glides, and one big finish — pop these on the fridge for the week.","items":["Do ten counted knee bounces once a day, ending with a hug.","Try the “more” sign after bounces and songs all week.","Take one slow flashlight-on-the-wall tour after dinner.","Dance one whole song together before bath time."]}}]},"jun":{"theme":"Sun, Sand & Splash","weeks":[{"label":"Week 1 — Hello, Sunshine","days":[{"day":"Monday","focus":"Morning Light","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Sunbeam Watch","d":"Lay baby near a bright window and watch the sunbeam together, wiggling your fingers to make shadows dance. Light and shadow are baby's first science show."},{"t":"Warm Spot, Cool Spot","d":"Touch baby's hand to a sun-warmed windowsill, then a cool floor tile, naming “warm… cool.” Comparing feels is how little explorers sort out their world."}]},{"day":"Tuesday","focus":"Sunshine Songs","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"You Are My Sunshine","d":"Sway with baby while singing “You Are My Sunshine,” smiling right into their eyes. A song sung just for them tells baby exactly how loved they are."},{"t":"Shady Alphabet Sing","d":"Spread a blanket in the shade and softly sing the ABCs while baby watches the leaves move. Letters are pure music at this age — the tune does the teaching."}]},{"day":"Wednesday","focus":"Shady Stretch","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Grass Blanket Tummy Time","d":"Take tummy time outside on a blanket in the shade, with fresh sounds and smells all around. New places make familiar exercise feel brand new (always supervise)."},{"t":"Sun Hat Peekaboo","d":"Hide your face behind a sun hat, then pop out with a warm “peekaboo.” Baby learns you always come back — that is trust, being built one giggle at a time."}]},{"day":"Thursday","focus":"Sunny Counting","domains":["Mathematical Thinking","Language & Literacy"],"opts":[{"t":"Eleven Little Claps","d":"Help baby clap along as you count to this month's number, eleven, in a singsong voice. Counting with hands moving lets baby feel the rhythm of numbers."},{"t":"Beach Book Lap Read","d":"Snuggle up with an ocean picture book like “Hello Ocean” and name what you see on each page. Reading in your lap is the warmest seat in the house."}]},{"day":"Friday","focus":"Porch Time","domains":["Social Studies","Physical Development"],"opts":[{"t":"Porch Hello","d":"Sit outside together and wave at whoever passes — a neighbor, a dog, the mail carrier. Baby is learning that friendly faces fill their community."},{"t":"Grass Toes","d":"Hold baby upright so their bare feet brush the grass, bouncing gently. New textures underfoot wake up the senses and strengthen little legs (always supervise)."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Hello, sunshine — four little rays to carry through the week.","items":["Take tummy time outside in the shade once this week.","Sing “You Are My Sunshine” at one diaper change a day.","Clap and count to eleven together at snack or bath time.","Wave at one neighbor or passerby from the porch or window."]}},{"label":"Week 2 — Splish & Splash","days":[{"day":"Monday","focus":"First Splashes","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Bowl Splash Pats","d":"Set a shallow bowl of water in front of seated baby and let them pat and splash. Every splash teaches cause and effect — always within arm's reach, every second."},{"t":"Warm Toe Dips","d":"Hold baby securely and dip just their toes into a shallow basin of warm water, in and out, saying “in… out.” Big giggles, tiny splashes — always within arm's reach."}]},{"day":"Tuesday","focus":"Water Songs","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Bath Time Row Boat","d":"Sing “Row, Row, Row Your Boat” during the bath, gently swishing baby's hands through the water on the beat. Songs plus splashes make words stick."},{"t":"Rain Bottle Shaker","d":"Fill a bottle with water, seal the lid tightly, and tilt it slowly so baby hears the swish. Homemade rain, safe in your hands (always supervise)."}]},{"day":"Wednesday","focus":"Float & Watch","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Sink or Float Show","d":"In a basin of water, drop in a spoon, then a plastic cup, narrating “down it goes… it floats.” Baby's eyes are doing real science watching each one."},{"t":"Melting Ice Show","d":"Seal an ice cube in a zip-top bag and let baby pat the cold while the summer sun slowly melts it into water — narrate the magic as it happens (always supervise, bag stays in your hand)."}]},{"day":"Thursday","focus":"Counting Drips","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Eleven Warm Drips","d":"At bath time, drip warm water gently onto baby's toes, counting each drip up to eleven. Numbers feel wonderful when they land as tiny warm taps."},{"t":"Washcloth Peekaboo","d":"Drape a washcloth lightly over your face at the tub, then pull it away with a soft “here I am.” The waiting and the reveal build trust and delight."}]},{"day":"Friday","focus":"Splash & Story","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Ocean Story Snuggle","d":"Wrap baby in a towel after the bath and share a splashy picture book together. Warm, dry, and read to — the coziest way to end a water week."},{"t":"Water Helpers Watch","d":"Carry baby along as you water plants or rinse dishes, narrating each step. Watching you care for your home is baby's first peek at how families work together."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Splish, splash — keep water play flowing at home, always within arm's reach.","items":["Offer a shallow bowl splash session once this week, towel at the ready.","Sing one water song during every bath.","Count eleven warm drips on toes at tub time.","Let baby watch you water a plant and narrate what you do."]}},{"label":"Week 3 — Sandy Toes & Textures","days":[{"day":"Monday","focus":"Sandy Feels","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Oatmeal Sandbox","d":"Pour dry oats into a tray and help baby pat and rake their fingers through this food-safe stand-in for sand. Gritty, soft, and pourable — a texture feast (always supervise)."},{"t":"Sandy Feet First","d":"If you visit real sand this week, hold baby so just their feet touch it first, warm and tickly. Feet are wonderful explorers — let them lead."}]},{"day":"Tuesday","focus":"Beach Sounds","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Ocean Shhh Sounds","d":"Make soft wave sounds near baby's ear — “shhh… whoosh… shhh” — slow and steady like the tide. Playful sounds like these tune baby's ear for language."},{"t":"Tickly Toes Rhyme","d":"Make up a little beach rhyme while walking your fingers up baby's legs like a sand crab. Rhyme, rhythm, and tickles are a language lesson in disguise."}]},{"day":"Wednesday","focus":"Climb & Pour","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Towel Mountain Crawl","d":"Roll up a few beach towels into low, squishy hills for baby to reach and wriggle over. A soft obstacle course builds strength and stick-with-it spirit (always supervise)."},{"t":"Scoop and Pour Show","d":"Slowly pour dry oats from one cup to another while baby watches the stream fall. Pouring is hypnotic to babies — and it plants the seeds of focused attention."}]},{"day":"Thursday","focus":"Big & Little","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Big Towel, Little Cloth","d":"Sweep a big beach towel gently over baby, then a little washcloth, saying “biiig… little.” Comparing sizes by feel is early math without a single number."},{"t":"Beach Baby Mirror","d":"Pop a sun hat on baby in front of the mirror and name the happy face you both see — feelings first, just like in “Your Feelings Matter.” Naming smiles teaches baby what joy is called."}]},{"day":"Friday","focus":"Aqua Everywhere","domains":["Social Studies","Scientific Inquiry"],"opts":[{"t":"Aqua Basket Explore","d":"Gather soft aqua and blue items — a cloth, a cup, a toy — into a basket for baby to explore. Naming this month's color as they touch each one links word to world."},{"t":"Family Beach Memories","d":"Look through photos of your family near water — pool days, beach trips, bath giggles — naming each person. Baby is learning the story of their own people."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Sandy toes and new textures — four easy feels for the diaper-bag list.","items":["Offer one tray of dry oats for supervised pat-and-rake play.","Make soft wave sounds — shhh, whoosh — at wind-down time.","Play big-and-little with a towel and washcloth after the bath.","Point out the color aqua once a day, on clothes, cups, or sky."]}},{"label":"Week 4 — By the Sea","days":[{"day":"Monday","focus":"Wave Motions","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Ocean Rock and Sway","d":"Hold baby close and sway in big, slow arcs like waves while you hum a rolling tune. Wave-rocking soothes the body while building balance."},{"t":"Scarf Waves","d":"Ripple a lightweight scarf slowly over baby like water rolling in, letting it brush their tummy. Watching it rise and fall is gentle magic for little eyes."}]},{"day":"Tuesday","focus":"Sea Sounds & Chats","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Whoosh in a Bottle","d":"Tilt a tightly sealed bottle of water slowly side to side near baby, listening to the whoosh together. Baby hears it, sees it, and starts connecting the two (always supervise)."},{"t":"Fishy Kisses Chat","d":"Make fishy-face kisses at baby, then pause and wait for a coo, wiggle, or grin in reply. That back-and-forth is a real conversation — the words come later."}]},{"day":"Wednesday","focus":"Reach & Rescue","domains":["Approaches to Learning","Scientific Inquiry"],"opts":[{"t":"Reach for the Boat","d":"Float a plastic cup in a shallow basin and let baby reach for their bobbing “boat.” Chasing something that drifts builds patience and problem-solving — always within arm's reach."},{"t":"Drip Drop Watch","d":"Hold a soaked washcloth high over the basin and let baby watch each drip fall and land. Up, then down, every single time — baby is soaking up how water works."}]},{"day":"Thursday","focus":"Seaside Counting","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Piggies Go Swimming","d":"Play this-little-piggy where each toe “goes swimming” instead of to market, counting as you go. Familiar rhymes with a seaside twist keep counting fresh."},{"t":"Eleven Is a Hug","d":"Count baby's ten fingers with a gentle tap each, then announce that eleven is a great big hug. Baby learns that counting ends somewhere warm."}]},{"day":"Friday","focus":"Summer Storytime","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Commotion Read-Aloud","d":"Close the month with a lively ocean book like “Commotion in the Ocean,” giving each creature a silly voice. Funny voices keep baby locked onto the language."},{"t":"Neighborhood Water Watch","d":"On a stroll, point out water at work in your community — sprinklers, fountains, a rain puddle. Baby's world gets bigger one wet and wonderful sight at a time."}]}],"homeden":{"title":"The Home Den — This Week","lead":"One last week by the sea — pop these four in the beach bag.","items":["Sway like waves with baby before naps this week.","Float a cup at bath time and let baby reach for the boat.","Count ten fingers, then make eleven a hug.","Point out one sprinkler, fountain, or puddle on your walks."]}}]},"jul":{"theme":"Imagination Station","weeks":[{"label":"Week 1 — Peekaboo & Pretend","days":[{"day":"Monday","focus":"Peekaboo Games","domains":["Social & Emotional Development","Approaches to Learning"],"opts":[{"t":"Classic Peekaboo","d":"Cover your face with your hands, pause, then pop out with a warm “peekaboo.” Baby is learning that hidden things still exist — and that you always come back."},{"t":"Blanket Pop-Up","d":"Hold a blanket between you and baby, lower it slowly, and greet them with a big smile each time. Stretch the pause a little longer as the game goes on."}]},{"day":"Tuesday","focus":"Silly Sounds","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Silly Face Copycat","d":"Make a slow silly face — big O mouth, waggling tongue — then wait and watch baby try it back. Copying faces is baby's first pretend play."},{"t":"Animal Sound Pretend","d":"Point to animal pictures or stuffed friends and give each a voice — “the cow says moooo.” Playful voices stretch baby's listening ear."}]},{"day":"Wednesday","focus":"Hide & Find","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Half-Hidden Toy","d":"Tuck a favorite toy halfway under a cloth and cheer as baby pulls it free. Finding hidden things is a genuine little experiment every single time."},{"t":"Knee Tunnel Peek","d":"Sit with your knees up, drape a blanket over them, and let baby peek and reach through the cozy tunnel. Reaching through builds arms and curiosity together (always supervise)."}]},{"day":"Thursday","focus":"Counting Peeks","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Twelve Little Peeks","d":"Count each peekaboo out loud, all the way to this month's number, twelve. The counting becomes part of the game's happy rhythm."},{"t":"Doorway Peep Game","d":"Step just out of sight at the door frame, then lean back in with a soft “here I am.” Short, playful disappearances help baby practice trusting your return."}]},{"day":"Friday","focus":"Pretend Together","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Phone Hello Pretend","d":"Hold a pretend phone to your ear, chat brightly, then hold it to baby's ear for their turn to babble. Baby is practicing how people talk to each other."},{"t":"Picture Book Peek","d":"Share a board book and pause before each page turn — “who is hiding on the next page?” A tiny drumroll turns reading into a guessing game."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Peekaboo week — four little games that fit anywhere, anytime.","items":["Play one round of peekaboo at every diaper change.","Half-hide a toy under a cloth once a day for baby to find.","Count twelve peeks out loud during the game.","Pause before each page turn at storytime and peek together."]}},{"label":"Week 2 — Puppet Pals","days":[{"day":"Monday","focus":"Puppet Hellos","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Sock Puppet Chat","d":"Slip a sock over your hand, give it a friendly voice, and let it say hello to baby. Pause after each puppet question so baby can answer with a coo or wiggle."},{"t":"Puppet Kiss Parade","d":"March the puppet up baby's arm with tiny pretend kisses, naming each stop — “elbow… shoulder… cheek.” Body words plus giggles is language at its stickiest."}]},{"day":"Tuesday","focus":"Reach for Puppets","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Puppet Chase Crawl","d":"Hop the puppet slowly across the floor just ahead of baby during tummy time, cheering every scoot toward it. A friend worth chasing makes exercise irresistible."},{"t":"High Puppet Stretch","d":"Fly the puppet gently overhead so baby reaches up with both hands to grab it. Let them win often — earned victories keep little explorers trying."}]},{"day":"Wednesday","focus":"Mirror Pretend","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Puppet in the Mirror","d":"Hold baby and the puppet up to the mirror and let the puppet wave at everyone it sees. Two babies, two puppets — figuring that out is real discovery work."},{"t":"Feelings Face Show","d":"Have the puppet act out a happy face, then a sleepy one, naming each feeling warmly. Hearing feelings named, over and over, is how baby learns theirs matter."}]},{"day":"Thursday","focus":"Puppet Counting","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Twelve Puppet Hops","d":"Hop the puppet gently up baby's tummy and arms while counting each hop to twelve. Counting that lands as tickles is counting baby asks for again."},{"t":"Puppet Toe Taps","d":"Let the puppet tap each of baby's toes with a number, then kick a soft “goodbye” at the end. Little taps make numbers something baby can feel."}]},{"day":"Friday","focus":"Puppet Storytime","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Puppet Reads Along","d":"Let the puppet help hold the book and gasp at the pictures while you read aloud. A co-reader with a funny voice doubles the storytime fun."},{"t":"Goodnight Wave Tour","d":"Carry baby and the puppet around the house waving goodnight to the lamp, the chair, the family photos. Little rituals like this teach how a home says goodnight."}]}],"homeden":{"title":"The Home Den — This Week","lead":"One sock plus your hand equals a best friend — here is puppet week at home.","items":["Keep a sock puppet in the diaper bag for waiting-room chats.","Let the puppet lead one tummy-time chase a day.","Count twelve puppet hops on baby's tummy at playtime.","Invite the puppet to storytime once this week."]}},{"label":"Week 3 — Little Music Makers","days":[{"day":"Monday","focus":"Dance Party","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Kitchen Dance Hold","d":"Put on a favorite song and dance around the kitchen with baby held snug against you. Dips, sways, and spins — gentle ones — are a full-body music lesson."},{"t":"Purple Scarf Twirl","d":"Twirl a purple scarf through the air to the music and let it drift down over baby's hands. This month's color, delivered as a slow-motion dance partner."}]},{"day":"Tuesday","focus":"Sound Discoveries","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Pot Drum Pats","d":"Flip a pot upside down and help baby pat the bottom with flat hands. Every pat makes a boom — baby is discovering they can make things happen."},{"t":"Loud and Soft Song","d":"Sing a line of any song in a big voice, then repeat it in a whisper, watching baby's face change. Volume is one of the first sound patterns babies notice."}]},{"day":"Wednesday","focus":"Musical Feelings","domains":["Approaches to Learning","Social & Emotional Development"],"opts":[{"t":"Happy Song, Sleepy Song","d":"Play a lively tune, then a slow lullaby, naming how each one feels — “this song is happy… this one is sleepy.” Baby is learning music carries feelings."},{"t":"If You're Happy Claps","d":"Sing “If You're Happy and You Know It” while gently helping baby's hands clap along. Pausing before each clap builds delicious anticipation."}]},{"day":"Thursday","focus":"Counting Beats","domains":["Mathematical Thinking","Creative Expression"],"opts":[{"t":"Twelve Drum Taps","d":"Tap a steady beat on the pot drum, counting out loud to twelve, then finish with a big flourish. A counted beat is rhythm and math holding hands."},{"t":"Pat-a-Cake Rhythm","d":"Play a slow, steady pat-a-cake, guiding baby's hands through the pattern. Clap, clap, roll — repeating patterns are the roots of mathematical thinking."}]},{"day":"Friday","focus":"Music Around Us","domains":["Social Studies","Physical Development"],"opts":[{"t":"Sounds of Home Tour","d":"Carry baby around to hear the house make music — the washer's hum, the doorbell, birds at the window. Every home has its own soundtrack worth naming."},{"t":"March and Bounce","d":"March around the room holding baby, bouncing lightly on the beat of a hummed tune. Feeling a steady beat through your whole body is how rhythm takes root."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Your kitchen is a concert hall this week — four notes to take home.","items":["Dance one full song together every day, baby held snug.","Offer the upside-down pot drum for one supervised jam session.","Sing one verse loud, then whisper it, and watch baby react.","Hum a marching beat during hallway carries."]}},{"label":"Week 4 — Story Magic","days":[{"day":"Monday","focus":"First Storytimes","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Imagination Read-Aloud","d":"Share an imagination book like “Not a Box,” letting baby pat the pages as you read. Long before the words make sense, your reading voice is pure comfort."},{"t":"Tell Baby's Day","d":"Turn baby's own day into a story — “once upon a time, a little one woke up and stretched…” Hearing their life narrated tells baby their story matters."}]},{"day":"Tuesday","focus":"Story Props","domains":["Scientific Inquiry","Creative Expression"],"opts":[{"t":"Texture Story Cloth","d":"Tell a tiny tale while baby feels each prop — a soft blanket cloud, a smooth cup moon, a bumpy towel road. Stories baby can touch live in the fingertips."},{"t":"Firefly Light Show","d":"Dim the room and dance a flashlight dot slowly across the wall like a firefly, narrating its adventure. Baby's eyes follow every move of the tale (always supervise)."}]},{"day":"Wednesday","focus":"Box Adventures","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Big Box Den","d":"Lay a big open box on its side as a cozy den for baby to reach into and explore, never closed. To a baby, a plain box is a castle — imagination needs nothing fancy (always supervise)."},{"t":"Pillow Path Quest","d":"Line up a few firm pillows into a winding path and cheer baby's wriggles along the “royal road.” A little quest makes big-muscle practice feel like play."}]},{"day":"Thursday","focus":"Counting Tales","domains":["Mathematical Thinking","Social Studies"],"opts":[{"t":"Twelve Goodnight Kisses","d":"Count twelve slow kisses at wind-down time — forehead, cheeks, tiny toes. This month's number becomes the sweetest part of the routine."},{"t":"Family Story Album","d":"Open a photo album and tell a one-line story for each person — “this is Grandpa, he grows tomatoes.” Baby is collecting the stories of their own family."}]},{"day":"Friday","focus":"Grand Finale Stories","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Feelings Book Finale","d":"Close the month with Mrs. Bear's own “Your Feelings Matter,” naming each feeling face slowly together. Feelings named early are feelings handled well later."},{"t":"Snuggle Week Recap","d":"At bedtime, retell the week as a story starring baby — the puppet, the box castle, the dancing. You are showing baby that memories are stories we keep."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Story magic to go — four page-turners for the diaper bag.","items":["Read one lap book a day, letting baby pat the pages.","Narrate one everyday moment as a once-upon-a-time story.","Give an open box five minutes as a play den, always supervised.","Count twelve goodnight kisses at bedtime this week."]}}]}};